        }
      } else {
        // Simulate successful registration
        const newUser: User = {
          id: `u${Date.now()}`,
          username: email.split('@')[0],
          email: email,
          full_name: fullName,
          is_active: true,
          role: role,
        };
        onLogin(newUser);
