import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog } from './types';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // 1. Initial Auth & Session Load
  useEffect(() => {
    const initializeAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', session.user.id)
          .single();

        if (profile) setCurrentUser(profile);
      }
      setIsInitializing(false);
    };

    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        const { data: profile } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', session.user.id)
          .single();
        if (profile) setCurrentUser(profile);
      } else {
        setCurrentUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // 2. Fetch Data when User is Authenticated
  useEffect(() => {
    if (!currentUser) return;

    const fetchData = async () => {
      const [
        { data: stData },
        { data: incData },
        { data: intData },
        { data: logData },
        { data: parentData },
        { data: repData },
        { data: auditData },
        { data: notifData }
      ] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('interventions').select('*'),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').eq('user_id', currentUser.id).order('created_at', { ascending: false })
      ]);

      if (stData) setStudents(stData);
      if (incData) setIncidents(incData);
      if (intData) setInterventions(intData);
      if (logData) setDeviceLogs(logData as any);
      if (parentData) setParents(parentData);
      if (repData) setReports(repData as any);
      if (auditData) setSystemLogs(auditData as any);
      if (notifData) setNotifications(notifData.map(n => ({
        id: n.id,
        title: n.title,
        message: n.message,
        timestamp: n.created_at,
        isRead: n.is_read,
        type: n.type
      })));
    };

    fetchData();

    // Subscribe to real-time notifications
    const channel = supabase.channel('realtime_updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'notifications', filter: `user_id=eq.${currentUser.id}` }, payload => {
        if (payload.eventType === 'INSERT') {
          const n = payload.new;
          setNotifications(prev => [{
            id: n.id,
            title: n.title,
            message: n.message,
            timestamp: n.created_at,
            isRead: n.is_read,
            type: n.type
          }, ...prev]);
        }
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [currentUser]);

  const addSystemLog = async (action: string, category: SystemLog['category'], user?: User) => {
    const logUser = user || currentUser;
    if (!logUser) return;

    const { data: logEntry } = await supabase.from('system_audit_logs').insert([{
      user_id: logUser.id,
      user_name: logUser.full_name,
      action,
      category,
      ip_address: 'Logged by Web Interface'
    }]).select().single();

    if (logEntry) {
      setSystemLogs(prev => [logEntry as any, ...prev]);
    }
  };

  const handleLogin = async (user: User) => {
    setCurrentUser(user);
    addSystemLog('System Authentication Successful', 'Access', user);
  };

  const handleLogout = async () => {
    await addSystemLog('User Initiated Logout', 'Access');
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const addNotification = async (notif: Omit<Notification, 'id' | 'timestamp' | 'isRead'>, userId?: string) => {
    const targetUserId = userId || currentUser?.id;
    if (!targetUserId) return;

    const { data } = await supabase.from('notifications').insert([{
      user_id: targetUserId,
      title: notif.title,
      message: notif.message,
      type: notif.type,
      is_read: false
    }]).select().single();

    if (data && targetUserId === currentUser?.id) {
       // Local state update if it's for current user (though real-time subscription also handles this)
    }
  };

  const markAllNotificationsRead = async () => {
    if (!currentUser) return;
    await supabase.from('notifications').update({ is_read: true }).eq('user_id', currentUser.id);
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const addIncident = async (newInc: Partial<Incident>) => {
    if (!currentUser) return;

    const { data, error } = await supabase.from('incidents').insert([{
      student_id: newInc.student_id,
      reported_by_user_id: currentUser.id,
      incident_type_id: newInc.incident_type_id,
      location: newInc.location,
      description: newInc.description,
      immediate_action: newInc.immediate_action,
      status: 'Pending',
      date_occurred: new Date().toISOString()
    }]).select().single();

    if (data) {
      setIncidents(prev => [data, ...prev]);
      const student = students.find(s => s.id === data.student_id);
      addNotification({
        title: 'New Incident Reported',
        message: `${student?.first_name} ${student?.last_name} has a new report: ${data.description.substring(0, 30)}...`,
        type: 'incident'
      });
      addSystemLog(`Created Incident Record for ${student?.last_name}`, 'Registry');
    }
  };

  const updateIncidentStatus = async (id: string, status: Incident['status']) => {
    const { data } = await supabase.from('incidents').update({ status }).eq('id', id).select().single();
    if (data) {
      setIncidents(prev => prev.map(inc => inc.id === id ? data : inc));
      addNotification({
        title: 'Incident Status Updated',
        message: `Case #${id.substring(0,8)} status changed to ${status}.`,
        type: 'system'
      });
      addSystemLog(`Modified Incident #${id.substring(0,8)} Status to ${status}`, 'Audit');
    }
  };

  const addGeneratedReport = async (report: GeneratedReport) => {
    if (!currentUser) return;
    const { data } = await supabase.from('generated_reports').insert([{
      title: report.title,
      type: report.type,
      generated_by_user_id: currentUser.id,
      status: 'Ready',
      file_size: report.file_size
    }]).select().single();

    if (data) {
      setReports(prev => [data as any, ...prev]);
      addNotification({
        title: 'Report Ready',
        message: `The "${report.title}" document is now available for download.`,
        type: 'report'
      });
      addSystemLog(`Generated System Report: ${report.type}`, 'Audit');
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-slate-900 rounded-xl mb-4 flex items-center justify-center text-white font-black">S</div>
          <div className="h-4 w-32 bg-slate-200 rounded"></div>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard':
        return <Dashboard incidents={incidents} students={students} />;
      case 'Students':
        return (
          <Students 
            currentUser={currentUser} 
            incidents={incidents} 
            students={students} 
            searchQuery={searchQuery}
            parents={parents}
            deviceLogs={deviceLogs}
          />
        );
      case 'Incidents':
        return (
          <Incidents 
            currentUser={currentUser} 
            incidents={incidents} 
            students={students} 
            onAddIncident={addIncident as any} 
            onUpdateStatus={updateIncidentStatus} 
            searchQuery={searchQuery} 
          />
        );
      case 'Interventions':
        return <Interventions currentUser={currentUser} incidents={incidents} students={students} interventions={interventions} />;
      case 'Reports':
        return <Reports currentUser={currentUser} reports={reports} onGenerateReport={addGeneratedReport} />;
      case 'System Logs':
        return <SystemLogs logs={systemLogs} />;
      case 'User Management':
        return <UserManagement />;
      default:
        return <Dashboard incidents={incidents} students={students} />;
    }
  };

  return (
    <Layout 
      user={currentUser} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      onLogout={handleLogout}
      searchQuery={searchQuery}
      setSearchQuery={setSearchQuery}
      notifications={notifications}
      onMarkRead={markAllNotificationsRead}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, Briefcase } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data, error: authError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (authError) throw authError;

        if (data.user) {
          const { data: profile, error: profError } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', data.user.id)
            .single();

          if (profError) throw profError;
          onLogin(profile);
        }
      } else {
        const { data, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: {
              full_name: fullName,
              role: role,
              username: email.split('@')[0],
            }
          }
        });

        if (authError) throw authError;

        if (data.user) {
          // In a real app, a trigger in Supabase would handle profile creation.
          // For immediate UI feedback, we can assume the profile is being created.
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', data.user.id)
            .single();

          if (profile) onLogin(profile);
          else setError('Account created. Please sign in.');
        }
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed. Check your credentials.');
    } finally {
      setIsLoading(false);
    }
  };

  const quickAccess = async (targetEmail: string) => {
    setEmail(targetEmail);
    setPassword('12345678');
    setIsLoginMode(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden">
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none">
        <div className="grid grid-cols-6 gap-20 p-20 transform -rotate-12">
          {Array.from({ length: 24 }).map((_, i) => (
            <Shield key={i} size={80} />
          ))}
        </div>
      </div>

      <div className="w-full max-w-md relative z-10 px-6">
        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden transition-all duration-300">
          <div className="p-8 pb-4 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-xl">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 mt-1 text-xs font-medium uppercase tracking-wider">
              {isLoginMode ? 'Officer Authentication' : 'Registry Enrollment'}
            </p>
          </div>

          <div className="px-8 flex border-b border-slate-100">
            <button
              onClick={() => setIsLoginMode(true)}
              className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${
                isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              Sign In
            </button>
            <button
              onClick={() => setIsLoginMode(false)}
              className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${
                !isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              Sign Up
            </button>
          </div>

          <form onSubmit={handleSubmit} className="p-8 pt-6 space-y-4">
            {error && (
              <div className="flex items-center gap-3 p-3 bg-amber-50 border border-amber-200 rounded-lg text-amber-900 text-[10px] animate-in fade-in duration-300">
                <AlertCircle size={16} className="shrink-0 text-amber-600" />
                <p className="font-bold uppercase tracking-tight">{error}</p>
              </div>
            )}

            <div className="space-y-3">
              {!isLoginMode && (
                <>
                  <div>
                    <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-widest">Official Full Name</label>
                    <div className="relative">
                      <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <input
                        type="text"
                        required
                        value={fullName}
                        onChange={(e) => setFullName(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-900 focus:ring-1 focus:ring-slate-900 outline-none transition-all placeholder:text-slate-400 font-medium"
                        placeholder="Juan Dela Cruz"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-widest">Designated Role</label>
                    <div className="relative">
                      <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <select
                        value={role}
                        onChange={(e) => setRole(e.target.value as any)}
                        className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-900 focus:ring-1 focus:ring-slate-900 outline-none transition-all appearance-none font-medium"
                      >
                        <option value="Teacher">Teacher (Academic Staff)</option>
                        <option value="Counselor">Guidance Counselor</option>
                      </select>
                    </div>
                  </div>
                </>
              )}

              <div>
                <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-widest">Official Work Email</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-900 focus:ring-1 focus:ring-slate-900 outline-none transition-all placeholder:text-slate-400 font-medium"
                    placeholder="official.email@school.edu"
                  />
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase tracking-widest">Access Password</label>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-900 focus:ring-1 focus:ring-slate-900 outline-none transition-all placeholder:text-slate-400 font-medium"
                    placeholder="••••••••"
                  />
                </div>
              </div>
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className="w-full py-3 bg-slate-900 text-white rounded-lg font-black text-xs uppercase tracking-widest hover:bg-slate-800 active:scale-[0.98] transition-all shadow-lg disabled:opacity-70 mt-2"
            >
              {isLoading ? (
                <span className="flex items-center justify-center gap-2">
                  <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  Verifying...
                </span>
              ) : isLoginMode ? 'Sign In to Portal' : 'Register New Account'}
            </button>
          </form>

          {isLoginMode && (
            <div className="px-8 pb-8">
              <div className="relative mb-6">
                <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
                <div className="relative flex justify-center text-[10px] uppercase font-bold tracking-widest"><span className="bg-white px-3 text-slate-400">Quick Access for Demo</span></div>
              </div>

              <div className="grid grid-cols-1 gap-2 text-center">
                <div className="flex justify-center gap-4">
                  <button onClick={() => quickAccess('teacher@gmail.com')} className="text-[10px] font-bold text-slate-500 hover:text-slate-900 transition-colors underline decoration-slate-200 hover:decoration-slate-900">Teacher</button>
                  <button onClick={() => quickAccess('counselor@gmail.com')} className="text-[10px] font-bold text-slate-500 hover:text-slate-900 transition-colors underline decoration-slate-200 hover:decoration-slate-900">Counselor</button>
                  <button onClick={() => quickAccess('admin@gmail.com')} className="text-[10px] font-bold text-slate-500 hover:text-slate-900 transition-colors underline decoration-slate-200 hover:decoration-slate-900">Admin</button>
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="mt-8 text-center space-y-3">
          <p className="text-slate-400 text-[9px] flex items-center justify-center gap-2 uppercase tracking-widest font-black">
            <Shield size={12} className="text-teal-600" />
            Compliant with RA 10173 - Data Privacy Act of 2012
          </p>
          <p className="text-slate-300 text-[8px] font-medium max-w-xs mx-auto">
            Authorized personnel only. All access attempts and activity are recorded for auditing purposes.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const initializeAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile);
      }
      setIsInitializing(false);
    };
    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile);
      } else {
        setCurrentUser(null);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!currentUser) return;

    const fetchData = async () => {
      const [
        { data: stData },
        { data: incData },
        { data: typeData },
        { data: intData },
        { data: logData },
        { data: parentData },
        { data: repData },
        { data: auditData },
        { data: notifData }
      ] = await Promise.all([
        supabase.from('students').select('*').order('last_name'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*').order('start_date', { ascending: false }),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*').order('date_generated', { ascending: false }),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').eq('user_id', currentUser.id).order('created_at', { ascending: false })
      ]);

      if (stData) setStudents(stData);
      if (incData) setIncidents(incData);
      if (typeData) setIncidentTypes(typeData);
      if (intData) setInterventions(intData);
      if (logData) setDeviceLogs(logData as any);
      if (parentData) setParents(parentData);
      if (repData) setReports(repData as any);
      if (auditData) setSystemLogs(auditData as any);
      if (notifData) setNotifications(notifData.map(n => ({
        id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
      })));
    };

    fetchData();

    const channel = supabase.channel('realtime_updates')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${currentUser.id}` }, payload => {
        const n = payload.new;
        setNotifications(prev => [{
          id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
        }, ...prev]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [currentUser]);

  const addSystemLog = async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const { data: logEntry } = await supabase.from('system_audit_logs').insert([{
      user_id: currentUser.id, user_name: currentUser.full_name, action, category, ip_address: 'Web-Client'
    }]).select().single();
    if (logEntry) setSystemLogs(prev => [logEntry as any, ...prev]);
  };

  const handleLogout = async () => {
    await addSystemLog('User Initiated Logout', 'Access');
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const addNotification = async (notif: Omit<Notification, 'id' | 'timestamp' | 'isRead'>, userId?: string) => {
    const targetUserId = userId || currentUser?.id;
    if (!targetUserId) return;
    await supabase.from('notifications').insert([{
      user_id: targetUserId, title: notif.title, message: notif.message, type: notif.type, is_read: false
    }]);
  };

  const addStudent = async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select().single();
    if (data) {
      setStudents(prev => [...prev, data].sort((a,b) => a.last_name.localeCompare(b.last_name)));
      addSystemLog(`Added new student: ${data.first_name} ${data.last_name}`, 'Registry');
    }
    return { data, error };
  };

  const addIncident = async (newInc: Partial<Incident>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('incidents').insert([{
      student_id: newInc.student_id, reported_by_user_id: currentUser.id, incident_type_id: newInc.incident_type_id,
      location: newInc.location, description: newInc.description, immediate_action: newInc.immediate_action,
      status: 'Pending', date_occurred: new Date().toISOString()
    }]).select().single();

    if (data) {
      setIncidents(prev => [data, ...prev]);
      const student = students.find(s => s.id === data.student_id);
      addNotification({
        title: 'New Incident Reported',
        message: `${student?.last_name} report: ${data.description.substring(0, 40)}...`,
        type: 'incident'
      });
      addSystemLog(`Registered incident for ${student?.last_name}`, 'Registry');
    }
  };

  const updateIncidentStatus = async (id: string, status: Incident['status']) => {
    const { data } = await supabase.from('incidents').update({ status }).eq('id', id).select().single();
    if (data) {
      setIncidents(prev => prev.map(inc => inc.id === id ? data : inc));
      addSystemLog(`Updated Incident Status to ${status}`, 'Audit');
    }
  };

  const addIntervention = async (intData: Partial<BehavioralIntervention>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('interventions').insert([{
      ...intData, assigned_by_user_id: currentUser.id
    }]).select().single();
    if (data) {
      setInterventions(prev => [data, ...prev]);
      addSystemLog(`Initialized intervention for student ID: ${data.student_id}`, 'Registry');
    }
  };

  const addGeneratedReport = async (report: GeneratedReport) => {
    if (!currentUser) return;
    const { data } = await supabase.from('generated_reports').insert([{
      title: report.title, type: report.type, generated_by_user_id: currentUser.id, status: 'Ready', file_size: report.file_size
    }]).select().single();
    if (data) setReports(prev => [data as any, ...prev]);
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-slate-900 rounded-xl mb-4 flex items-center justify-center text-white font-black">S</div>
          <div className="h-4 w-32 bg-slate-200 rounded"></div>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={(u) => { setCurrentUser(u); addSystemLog('Login Success', 'Access'); }} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={incidents} students={students} />;
      case 'Students': return <Students currentUser={currentUser} incidents={incidents} students={students} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={addStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={incidents} students={students} incidentTypes={incidentTypes} onAddIncident={addIncident as any} onUpdateStatus={updateIncidentStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={students} interventions={interventions} onAddIntervention={addIntervention} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={addGeneratedReport} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement />;
      default: return <Dashboard incidents={incidents} students={students} />;
    }
  };

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={async () => {
      await supabase.from('notifications').update({ is_read: true }).eq('user_id', currentUser.id);
      setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
    }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Search, Plus, MapPin, BrainCircuit, Users, ShieldAlert, Lock, X, Phone, Mail, Tablet } from 'lucide-react';
import { getBehavioralInsight } from '../services/geminiService';
import { User, Student, Incident, ParentGuardian, DeviceUsageRecord } from '../types';

interface StudentsProps {
  currentUser: User;
  students: Student[];
  incidents: Incident[];
  parents: ParentGuardian[];
  deviceLogs: DeviceUsageRecord[];
  searchQuery: string;
  onAddStudent: (data: Partial<Student>) => Promise<any>;
}

const Students: React.FC<StudentsProps> = ({ currentUser, students, incidents, parents, deviceLogs, searchQuery, onAddStudent }) => {
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStudent, setNewStudent] = useState<Partial<Student>>({
    lrn: '', first_name: '', last_name: '', grade_level: '7', section: '', address: '', gender: 'Male'
  });

  const filteredStudents = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return students.filter(s => 
      s.first_name.toLowerCase().includes(q) || s.last_name.toLowerCase().includes(q) || s.lrn.includes(q)
    );
  }, [students, searchQuery]);

  const selectedStudent = useMemo(() => students.find(s => s.id === selectedStudentId), [students, selectedStudentId]);
  const studentParent = useMemo(() => parents.find(p => p.student_id === selectedStudentId), [parents, selectedStudentId]);
  const studentLogs = useMemo(() => deviceLogs.filter(l => l.student_id === selectedStudentId), [deviceLogs, selectedStudentId]);

  const canManage = currentUser.role !== 'Teacher';

  const handleAnalyze = async (studentId: string) => {
    setIsAnalyzing(true);
    const history = incidents.filter(inc => inc.student_id === studentId);
    const result = await getBehavioralInsight(history);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const handleAddSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    await onAddStudent({ ...newStudent, date_of_birth: new Date().toISOString() });
    setIsModalOpen(false);
    setNewStudent({ lrn: '', first_name: '', last_name: '', grade_level: '7', section: '', address: '', gender: 'Male' });
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-1 bg-white border border-slate-200 rounded-xl flex flex-col h-[calc(100vh-10rem)] shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 space-y-4 bg-slate-50/50">
          <div className="flex justify-between items-center">
            <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Official Registry</h3>
            {canManage && (
              <button onClick={() => setIsModalOpen(true)} className="p-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors shadow-sm">
                <Plus size={14} />
              </button>
            )}
          </div>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
            <input type="text" placeholder="Filter Registry..." className="w-full pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-xs font-medium focus:ring-1 focus:ring-teal-500 outline-none" onChange={(e) => {}} />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto divide-y divide-slate-100">
          {filteredStudents.length > 0 ? filteredStudents.map(student => (
            <button key={student.id} onClick={() => { setSelectedStudentId(student.id); setAiAnalysis(null); }} className={`w-full p-5 flex items-center gap-4 hover:bg-slate-50 transition-all text-left group ${selectedStudentId === student.id ? 'bg-teal-50/50 border-l-4 border-teal-600' : ''}`}>
              <div className="w-10 h-10 rounded-lg bg-slate-900 flex items-center justify-center text-white text-xs font-black shadow-sm group-hover:scale-110 transition-transform">
                {student.first_name[0]}{student.last_name[0]}
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-sm font-bold text-slate-900 tracking-tight">{student.first_name} {student.last_name}</p>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">LRN: {student.lrn}</p>
              </div>
            </button>
          )) : (
            <div className="p-8 text-center text-slate-400">
              <p className="text-[10px] font-black uppercase tracking-widest">No Students Found</p>
            </div>
          )}
        </div>
      </div>

      <div className="lg:col-span-2 space-y-6">
        {selectedStudent ? (
          <div className="animate-in slide-in-from-right-4 duration-500">
            <div className="bg-white border border-slate-200 rounded-xl p-8 shadow-sm">
              <div className="flex items-start justify-between mb-8">
                <div className="flex items-center gap-6">
                  <div className="w-24 h-24 rounded-2xl bg-slate-900 flex items-center justify-center text-white text-4xl font-black shadow-2xl border-4 border-white">
                    {selectedStudent.first_name[0]}{selectedStudent.last_name[0]}
                  </div>
                  <div>
                    <h2 className="text-2xl font-bold text-slate-900 tracking-tight">{selectedStudent.first_name} {selectedStudent.last_name}</h2>
                    <p className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Grade {selectedStudent.grade_level} • Section {selectedStudent.section}</p>
                    <div className="flex items-center gap-4 mt-3 text-xs text-slate-400 font-medium">
                      <span className="flex items-center gap-1.5"><MapPin size={14} className="text-teal-600" /> {selectedStudent.address}</span>
                    </div>
                  </div>
                </div>
                {canManage && (
                  <button onClick={() => handleAnalyze(selectedStudent.id)} disabled={isAnalyzing} className="px-4 py-2 bg-teal-700 text-white rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-teal-800 flex items-center gap-2 disabled:opacity-50 transition-all shadow-lg active:scale-95">
                    <BrainCircuit size={16} /> {isAnalyzing ? 'Analyzing...' : 'AI Welfare Check'}
                  </button>
                )}
              </div>

              {aiAnalysis && (
                <div className="mb-8 p-6 bg-teal-900 text-white rounded-xl shadow-xl animate-in zoom-in-95 duration-300 relative overflow-hidden">
                  <div className="relative z-10">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-2">
                        <ShieldAlert className="text-teal-400" size={18} />
                        <h4 className="text-[10px] font-black uppercase tracking-widest">Confidential Welfare Insight</h4>
                      </div>
                      <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded bg-white/10 ${aiAnalysis.riskLevel === 'High' ? 'text-red-300' : 'text-teal-300'}`}>
                        Risk: {aiAnalysis.riskLevel}
                      </span>
                    </div>
                    <p className="text-sm text-teal-50 leading-relaxed font-medium mb-4">{aiAnalysis.analysis}</p>
                    <div className="space-y-2">
                      <p className="text-[10px] font-black text-teal-400 uppercase tracking-widest">Recommended Procedures:</p>
                      <ul className="grid grid-cols-1 md:grid-cols-2 gap-2">
                        {aiAnalysis.suggestedInterventions.map((item: string, i: number) => (
                          <li key={i} className="flex items-center gap-2 text-xs font-bold text-teal-100 bg-white/5 p-2 rounded border border-white/5">
                            <div className="w-1 h-1 rounded-full bg-teal-400"></div>{item}
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>
                  <button onClick={() => setAiAnalysis(null)} className="absolute top-4 right-4 text-white/40 hover:text-white"><X size={16} /></button>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6 border-t border-slate-100">
                <div>
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Parent/Guardian Info</h4>
                  {studentParent ? (
                    <div className="space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-100">
                      <p className="text-sm font-bold text-slate-800">{studentParent.first_name} {studentParent.last_name}</p>
                      <div className="space-y-2">
                        <p className="text-[10px] text-slate-500 font-bold flex items-center gap-2 uppercase tracking-tighter"><Phone size={12} className="text-teal-600" /> {studentParent.contact_number}</p>
                        <p className="text-[10px] text-slate-500 font-bold flex items-center gap-2 uppercase tracking-tighter"><Mail size={12} className="text-teal-600" /> {studentParent.email}</p>
                      </div>
                    </div>
                  ) : <p className="text-xs italic text-slate-400">No linked guardian record.</p>}
                </div>
                <div>
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Digital Monitoring</h4>
                  <div className="space-y-2">
                    {studentLogs.length > 0 ? studentLogs.slice(0, 3).map(log => (
                      <div key={log.id} className={`p-3 rounded-lg border flex items-center gap-3 ${log.flagged ? 'bg-red-50 border-red-100' : 'bg-slate-50 border-slate-100'}`}>
                        <Tablet size={14} className={log.flagged ? 'text-red-500' : 'text-slate-400'} />
                        <div className="flex-1 overflow-hidden">
                          <p className="text-[10px] font-bold text-slate-800 truncate">{log.activity_description}</p>
                          <p className="text-[9px] text-slate-400 uppercase font-black">{new Date(log.usage_start).toLocaleDateString()}</p>
                        </div>
                      </div>
                    )) : <p className="text-xs italic text-slate-400">No recent activity logs.</p>}
                  </div>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="h-full border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center text-slate-400 bg-white/50">
            <Users size={64} className="mb-4 opacity-5" />
            <p className="text-[10px] font-black uppercase tracking-widest">Select Subject for Verification</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Register New Student</h3>
              <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">First Name</label>
                  <input required type="text" value={newStudent.first_name} onChange={(e) => setNewStudent({...newStudent, first_name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-teal-500 outline-none" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Last Name</label>
                  <input required type="text" value={newStudent.last_name} onChange={(e) => setNewStudent({...newStudent, last_name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-teal-500 outline-none" />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">LRN (Learner Reference Number)</label>
