import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, Briefcase } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;
        if (data.user) {
          const { data: profile, error: profError } = await supabase.from('profiles').select('*').eq('id', data.user.id).single();
          if (profError) throw profError;
          onLogin(profile);
        }
      } else {
        const { data, error: authError } = await supabase.auth.signUp({ 
          email, password, options: { data: { full_name: fullName, role: role } } 
        });
        if (authError) throw authError;
        if (data.user) {
          // Explicit profile creation in case triggers are not active
          const { data: profile, error: createError } = await supabase.from('profiles').insert([{
            id: data.user.id,
            username: email.split('@')[0],
            full_name: fullName,
            role: role,
            is_active: true
          }]).select().single();

          if (profile) onLogin(profile);
          else if (createError) throw createError;
          else setError('Profile created. Please sign in.');
        }
      }
    } catch (err: any) {
      setError(err.message || 'Authentication error.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden">
      <div className="w-full max-w-md relative z-10 px-6">
        <div className="bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="p-8 pb-4 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-xl"><ShieldCheck size={32} /></div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 mt-1 text-xs font-medium uppercase tracking-wider">{isLoginMode ? 'Officer Authentication' : 'Registry Enrollment'}</p>
          </div>
          <div className="px-8 flex border-b border-slate-100">
            <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign In</button>
            <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign Up</button>
          </div>
          <form onSubmit={handleSubmit} className="p-8 space-y-4">
            {error && <div className="p-3 bg-amber-50 border border-amber-200 rounded-lg text-amber-900 text-[10px] font-bold uppercase tracking-tight flex items-center gap-2"><AlertCircle size={14}/>{error}</div>}
            <div className="space-y-3">
              {!isLoginMode && (
                <>
                  <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm" placeholder="Full Name" />
                  <select value={role} onChange={(e) => setRole(e.target.value as any)} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm">
                    <option value="Teacher">Teacher (Academic)</option>
                    <option value="Counselor">Counselor (Guidance)</option>
                  </select>
                </>
              )}
              <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm" placeholder="Work Email" />
              <input required type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm" placeholder="Password" />
            </div>
            <button type="submit" disabled={isLoading} className="w-full py-3 bg-slate-900 text-white rounded-lg font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg">
              {isLoading ? 'Verifying...' : isLoginMode ? 'Enter Portal' : 'Register Authority'}
            </button>
          </form>
        </div>
        <p className="mt-8 text-center text-slate-400 text-[9px] uppercase tracking-widest font-black">Authorized Internal Access Registry</p>
      </div>
    </div>
  );
};

export default Login;

