import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, Briefcase, Database, CheckCircle2, Loader2 } from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'exists' | 'error';
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;
        if (data.user) {
          const { data: profile, error: profError } = await supabase.from('profiles').select('*').eq('id', data.user.id).single();
          if (profError) throw profError;
          onLogin(profile);
        }
      } else {
        const { data, error: authError } = await supabase.auth.signUp({ 
          email, password, options: { data: { full_name: fullName, role: role } } 
        });
        if (authError) throw authError;
        if (data.user) {
          const { data: profile, error: createError } = await supabase.from('profiles').insert([{
            id: data.user.id,
            username: email.split('@')[0],
            full_name: fullName,
            role: role,
            is_active: true
          }]).select().single();

          if (profile) onLogin(profile);
          else if (createError) throw createError;
          else setError('Profile created. Please sign in.');
        }
      }
    } catch (err: any) {
      setError(err.message || 'Authentication error. Please check credentials or initialize demo accounts.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        // 1. Register with Auth
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        if (signUpError) {
          if (signUpError.message.includes('already registered')) {
            setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'exists' } : s));
          } else {
            throw signUpError;
          }
        } else if (authData?.user) {
          // 2. Register Profile row
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: authData.user.id,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;
          setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'success' } : s));
        }
      } catch (err: any) {
        console.error(err);
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'error' } : s));
      }
    }
  };

  const quickAccess = async (targetEmail: string) => {
    setEmail(targetEmail);
    setPassword('12345678');
    setIsLoginMode(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="w-full max-w-md relative z-10">
