          <div className="p-8 pb-4 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-xl border border-slate-700">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 mt-1 text-xs font-medium uppercase tracking-wider">
              {isSeeding ? 'Demo Environment Setup' : isLoginMode ? 'Officer Authentication' : 'Registry Enrollment'}
            </p>
          </div>

          {isSeeding ? (
            <div className="p-8 space-y-6 animate-in fade-in zoom-in-95 duration-300">
              <div className="space-y-3">
                {seedStep.map((step, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{step.email}</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{step.role}</span>
                    </div>
                    <div>
                      {step.status === 'loading' && <Loader2 size={16} className="text-teal-600 animate-spin" />}
                      {step.status === 'success' && <CheckCircle2 size={16} className="text-teal-600" />}
                      {step.status === 'exists' && <div className="text-[9px] font-black uppercase bg-teal-50 text-teal-700 px-2 py-1 rounded">Already Setup</div>}
                      {step.status === 'error' && <AlertCircle size={16} className="text-red-500" />}
                      {step.status === 'pending' && <div className="w-4 h-4 rounded-full border border-slate-200"></div>}
                    </div>
                  </div>
                ))}
              </div>
              <button 
                onClick={() => setIsSeeding(false)}
                className="w-full py-3 bg-slate-900 text-white rounded-lg font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"
              >
                Return to Login
              </button>
            </div>
          ) : (
            <>
              <div className="px-8 flex border-b border-slate-100">
                <button 
                  onClick={() => setIsLoginMode(true)} 
                  className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}
                >
                  Sign In
                </button>
                <button 
                  onClick={() => setIsLoginMode(false)} 
                  className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}
                >
                  Sign Up
