import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const initializeAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile);
      }
      setIsInitializing(false);
    };
    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile);
      } else {
        setCurrentUser(null);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!currentUser) return;

    const fetchData = async () => {
      const [
        { data: stData },
        { data: incData },
        { data: typeData },
        { data: intData },
        { data: logData },
        { data: parentData },
        { data: repData },
        { data: auditData },
        { data: notifData }
      ] = await Promise.all([
        supabase.from('students').select('*').order('last_name'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*').order('start_date', { ascending: false }),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*').order('date_generated', { ascending: false }),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').eq('user_id', currentUser.id).order('created_at', { ascending: false })
      ]);

      if (stData) setStudents(stData);
      if (incData) setIncidents(incData);
      if (typeData) setIncidentTypes(typeData);
      if (intData) setInterventions(intData);
      if (logData) setDeviceLogs(logData as any);
      if (parentData) setParents(parentData);
      if (repData) setReports(repData as any);
      if (auditData) setSystemLogs(auditData as any);
      if (notifData) setNotifications(notifData.map(n => ({
        id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
      })));
    };

    fetchData();

    const channel = supabase.channel('realtime_updates')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${currentUser.id}` }, payload => {
        const n = payload.new;
        setNotifications(prev => [{
          id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
        }, ...prev]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [currentUser]);

  const addSystemLog = async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const { data: logEntry } = await supabase.from('system_audit_logs').insert([{
      user_id: currentUser.id, user_name: currentUser.full_name, action, category, ip_address: 'Web-Client'
    }]).select().single();
    if (logEntry) setSystemLogs(prev => [logEntry as any, ...prev]);
  };

  const handleLogout = async () => {
    await addSystemLog('User Initiated Logout', 'Access');
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const addNotification = async (notif: Omit<Notification, 'id' | 'timestamp' | 'isRead'>, userId?: string) => {
    const targetUserId = userId || currentUser?.id;
    if (!targetUserId) return;
    await supabase.from('notifications').insert([{
      user_id: targetUserId, title: notif.title, message: notif.message, type: notif.type, is_read: false
    }]);
  };

  const addStudent = async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select().single();
    if (data) {
      setStudents(prev => [...prev, data].sort((a,b) => a.last_name.localeCompare(b.last_name)));
      addSystemLog(`Added new student: ${data.first_name} ${data.last_name}`, 'Registry');
    }
    return { data, error };
  };

  const addIncident = async (newInc: Partial<Incident>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('incidents').insert([{
      student_id: newInc.student_id, reported_by_user_id: currentUser.id, incident_type_id: newInc.incident_type_id,
      location: newInc.location, description: newInc.description, immediate_action: newInc.immediate_action,
      status: 'Pending', date_occurred: new Date().toISOString()
    }]).select().single();

    if (data) {
      setIncidents(prev => [data, ...prev]);
      const student = students.find(s => s.id === data.student_id);
      addNotification({
        title: 'New Incident Reported',
        message: `${student?.last_name} report: ${data.description.substring(0, 40)}...`,
        type: 'incident'
      });
      addSystemLog(`Registered incident for ${student?.last_name}`, 'Registry');
    }
  };

  const updateIncidentStatus = async (id: string, status: Incident['status']) => {
    const { data } = await supabase.from('incidents').update({ status }).eq('id', id).select().single();
    if (data) {
      setIncidents(prev => prev.map(inc => inc.id === id ? data : inc));
      addSystemLog(`Updated Incident Status to ${status}`, 'Audit');
    }
  };

  const addIntervention = async (intData: Partial<BehavioralIntervention>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('interventions').insert([{
      ...intData, assigned_by_user_id: currentUser.id
    }]).select().single();
    if (data) {
      setInterventions(prev => [data, ...prev]);
      addSystemLog(`Initialized intervention for student ID: ${data.student_id}`, 'Registry');
    }
  };

  const addGeneratedReport = async (report: GeneratedReport) => {
    if (!currentUser) return;
    const { data } = await supabase.from('generated_reports').insert([{
      title: report.title, type: report.type, generated_by_user_id: currentUser.id, status: 'Ready', file_size: report.file_size
    }]).select().single();
    if (data) setReports(prev => [data as any, ...prev]);
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-slate-900 rounded-xl mb-4 flex items-center justify-center text-white font-black shadow-xl">S</div>
          <div className="h-4 w-32 bg-slate-200 rounded"></div>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={(u) => { setCurrentUser(u); addSystemLog('Login Success', 'Access'); }} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={incidents} students={students} />;
      case 'Students': return <Students currentUser={currentUser} incidents={incidents} students={students} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={addStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={incidents} students={students} incidentTypes={incidentTypes} onAddIncident={addIncident as any} onUpdateStatus={updateIncidentStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={students} interventions={interventions} onAddIntervention={addIntervention} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={addGeneratedReport} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement />;
      default: return <Dashboard incidents={incidents} students={students} />;
    }
  };

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={async () => {
      await supabase.from('notifications').update({ is_read: true }).eq('user_id', currentUser.id);
      setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
    }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, Briefcase, Database, CheckCircle2, Loader2, Info } from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'healed' | 'error' | 'needs_verification';
  message?: string;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      // 1. Authenticate with Supabase Auth
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });

      if (authError) {
        if (authError.message.includes('Email not confirmed')) {
          throw new Error('Email not confirmed. Please disable "Confirm Email" in your Supabase Auth Settings.');
        }
        throw authError;
      }

      if (authData.user) {
        // 2. Fetch the custom profile
        const { data: profile, error: profError } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', authData.user.id)
          .single();

        if (profError) {
          // If profile is missing, try to create it on the fly for the demo
          const metadata = authData.user.user_metadata;
          const { data: newProfile, error: createError } = await supabase.from('profiles').insert([{
            id: authData.user.id,
            username: email.split('@')[0],
            full_name: metadata?.full_name || 'System User',
            role: metadata?.role || 'Teacher',
            is_active: true
          }]).select().single();

          if (createError) throw new Error("Profile missing and auto-creation failed. Please use the 'Initialize' button.");
          onLogin(newProfile);
        } else {
          onLogin(profile);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Invalid credentials. Ensure accounts are initialized.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        // Step A: Attempt Sign Up
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        let userId = authData?.user?.id;

        // Step B: Handle existing user (Heal Mode)
        if (signUpError?.message?.includes('already registered')) {
          // If user exists, we sign in briefly to get the ID and ensure profile exists
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email: account.email,
            password: account.password
          });

          if (signInError) throw signInError;
          userId = signInData.user?.id;
        } else if (signUpError) {
          throw signUpError;
        }

        // Step C: Upsert Profile
        if (userId) {
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: userId,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;

          setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
            ...s, 
            status: signUpError ? 'healed' : 'success' 
          } : s));
        }

        // Final step: Logout to clear the session used for seeding
        await supabase.auth.signOut();

      } catch (err: any) {
        console.error(err);
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
          ...s, 
          status: 'error', 
          message: err.message 
        } : s));
      }
    }
  };

  const quickAccess = async (targetEmail: string) => {
    setEmail(targetEmail);
    setPassword('12345678');
    setIsLoginMode(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="w-full max-w-md relative z-10">
        <div className="bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden transition-all duration-500">
          <div className="p-8 pb-4 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-xl border border-slate-700">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 mt-1 text-xs font-medium uppercase tracking-wider">
              {isSeeding ? 'Demo Environment Setup' : isLoginMode ? 'Officer Authentication' : 'Registry Enrollment'}
            </p>
          </div>

          {isSeeding ? (
            <div className="p-8 space-y-6 animate-in fade-in zoom-in-95 duration-300">
              <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex gap-3 items-start">
                <Info size={16} className="text-blue-600 shrink-0 mt-0.5" />
                <p className="text-[10px] text-blue-800 font-medium leading-relaxed">
                  Initializing demo accounts. If you see errors, ensure <strong>Email Confirmation</strong> is disabled in your Supabase Auth settings.
                </p>
              </div>

              <div className="space-y-3">
                {seedStep.map((step, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{step.email}</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{step.role}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      {step.status === 'loading' && <Loader2 size={16} className="text-teal-600 animate-spin" />}
                      {step.status === 'success' && <div className="text-[9px] font-black uppercase bg-teal-50 text-teal-700 px-2 py-1 rounded">Created</div>}
                      {step.status === 'healed' && <div className="text-[9px] font-black uppercase bg-blue-50 text-blue-700 px-2 py-1 rounded">Healed</div>}
                      {step.status === 'error' && <div className="group relative"><AlertCircle size={16} className="text-red-500 cursor-help" /><div className="hidden group-hover:block absolute bottom-full right-0 mb-2 w-48 p-2 bg-slate-900 text-white text-[8px] rounded shadow-xl">{step.message}</div></div>}
                      {step.status === 'pending' && <div className="w-4 h-4 rounded-full border border-slate-200"></div>}
                    </div>
                  </div>
                ))}
              </div>
              <button 
                onClick={() => setIsSeeding(false)}
                className="w-full py-3 bg-slate-900 text-white rounded-lg font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"
              >
                Go to Login
              </button>
            </div>
          ) : (
            <>
              <div className="px-8 flex border-b border-slate-100">
                <button 
                  onClick={() => setIsLoginMode(true)} 
                  className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}
                >
                  Sign In
                </button>
                <button 
                  onClick={() => setIsLoginMode(false)} 
                  className={`flex-1 py-3 text-xs font-bold uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}
                >
                  Sign Up
                </button>
              </div>

              <form onSubmit={handleSubmit} className="p-8 space-y-4">
                {error && (
                  <div className="p-3 bg-red-50 border border-red-100 rounded-lg text-red-900 text-[10px] font-bold uppercase tracking-tight flex items-start gap-2 animate-in slide-in-from-top-1">
                    <AlertCircle size={14} className="text-red-600 shrink-0 mt-0.5" />
                    <span>{error}</span>
                  </div>
                )}

                <div className="space-y-3">
                  {!isLoginMode && (
                    <>
                      <div className="relative">
                        <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input 
                          required 
                          type="text" 
                          value={fullName} 
                          onChange={(e) => setFullName(e.target.value)} 
                          className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-slate-900 outline-none" 
                          placeholder="Full Official Name" 
                        />
                      </div>
                      <div className="relative">
                        <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <select 
                          value={role} 
                          onChange={(e) => setRole(e.target.value as any)} 
                          className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm appearance-none focus:ring-1 focus:ring-slate-900 outline-none"
                        >
                          <option value="Teacher">Academic Staff (Teacher)</option>
                          <option value="Counselor">Guidance Officer (Counselor)</option>
                          <option value="Administrator">System Admin (Admin)</option>
                        </select>
                      </div>
                    </>
                  )}
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                      required 
                      type="email" 
                      value={email} 
                      onChange={(e) => setEmail(e.target.value)} 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-slate-900 outline-none" 
                      placeholder="Official Work Email" 
                    />
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                      required 
                      type="password" 
                      value={password} 
                      onChange={(e) => setPassword(e.target.value)} 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-slate-900 outline-none" 
                      placeholder="Access Password" 
                    />
                  </div>
                </div>

                <button 
                  type="submit" 
                  disabled={isLoading} 
                  className="w-full py-3 bg-slate-900 text-white rounded-lg font-black text-xs uppercase tracking-widest hover:bg-slate-800 active:scale-[0.98] transition-all shadow-lg disabled:opacity-70"
                >
                  {isLoading ? (
                    <span className="flex items-center justify-center gap-2">
                      <Loader2 size={16} className="animate-spin" />
                      Verifying...
                    </span>
                  ) : isLoginMode ? 'Sign In' : 'Register'}
                </button>
              </form>

              {isLoginMode && (
                <div className="px-8 pb-8">
                  <div className="relative mb-6">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
                    <div className="relative flex justify-center text-[10px] uppercase font-bold tracking-widest">
                      <span className="bg-white px-3 text-slate-400">Demo Quick Access</span>
                    </div>
                  </div>

                  <div className="grid grid-cols-3 gap-2 mb-6">
                    <button onClick={() => quickAccess('teacher@gmail.com')} className="py-2 px-1 border border-slate-200 rounded text-[9px] font-black uppercase tracking-tighter hover:bg-slate-50 text-slate-600 transition-colors">Teacher</button>
                    <button onClick={() => quickAccess('counselor@gmail.com')} className="py-2 px-1 border border-slate-200 rounded text-[9px] font-black uppercase tracking-tighter hover:bg-slate-50 text-slate-600 transition-colors">Counselor</button>
                    <button onClick={() => quickAccess('admin@gmail.com')} className="py-2 px-1 border border-slate-200 rounded text-[9px] font-black uppercase tracking-tighter hover:bg-slate-50 text-slate-600 transition-colors">Admin</button>
                  </div>

                  <button 
                    onClick={handleInitializeDemo}
                    className="w-full flex items-center justify-center gap-2 py-3 px-4 bg-teal-50 text-teal-700 border border-teal-100 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-teal-100 transition-all group"
                  >
                    <Database size={12} className="group-hover:animate-bounce" />
                    Register / Repair Demo Accounts
                  </button>
                  <p className="text-[9px] text-center text-slate-400 mt-3 font-bold uppercase tracking-tight">Default Password: 12345678</p>
                </div>
              )}
            </>
          )}
        </div>

        <div className="mt-8 text-center space-y-3">
          <p className="text-slate-400 text-[9px] flex items-center justify-center gap-2 uppercase tracking-widest font-black">
            <Shield size={12} className="text-teal-600" />
            Authorized Educational Environment
          </p>
        </div>
      </div>
    </div>
  );
};

