import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, 
  Briefcase, Database, CheckCircle2, Loader2, Info, Terminal, 
  ChevronRight, Settings, Copy, Code, AlertTriangle, X, CheckCircle,
  Zap, DatabaseZap
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'healed' | 'error';
  message?: string;
}

const REQUIRED_TABLES = [
  'profiles', 'students', 'incidents', 'incident_types', 
  'interventions', 'device_logs', 'parents', 
  'generated_reports', 'system_audit_logs', 'notifications'
];

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSql, setShowSql] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);

  // Connectivity Stats
  const [missingTables, setMissingTables] = useState<string[]>([]);
  const [dbStatus, setDbStatus] = useState<'checking' | 'online' | 'missing_tables' | 'offline'>('checking');

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  useEffect(() => {
    checkDatabase();
  }, []);

  const checkDatabase = async () => {
    setDbStatus('checking');
    const missing: string[] = [];

    try {
      for (const table of REQUIRED_TABLES) {
        const { error } = await supabase.from(table).select('id').limit(1);
        // Error code 42P01 is Postgres for "table does not exist"
        if (error && (error.code === '42P01' || error.message.includes('does not exist'))) {
          missing.push(table);
        }
      }

      if (missing.length > 0) {
        setMissingTables(missing);
        setDbStatus('missing_tables');
      } else {
        setDbStatus('online');
      }
    } catch (e) {
      setDbStatus('offline');
    }
  };

  const generateSql = () => {
    return `
-- ==========================================
-- SAFE-EDU EMERGENCY SCHEMA & RLS REPAIR
-- ==========================================

-- 1. Profiles (Critical for Authentication)
CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    username TEXT UNIQUE,
    full_name TEXT,
    role TEXT CHECK (role IN ('Teacher', 'Counselor', 'Administrator')),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- FIX RLS FOR PROFILES (Prevents 'violates row-level security policy' error)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public All" ON public.profiles;
CREATE POLICY "Public All" ON public.profiles FOR ALL USING (true) WITH CHECK (true);

-- 2. Core Operational Tables
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    lrn TEXT UNIQUE NOT NULL,
    first_name TEXT, last_name TEXT, date_of_birth DATE,
    gender TEXT, grade_level TEXT, section TEXT, address TEXT, contact_number TEXT
);
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public All Students" ON public.students;
CREATE POLICY "Public All Students" ON public.students FOR ALL USING (true) WITH CHECK (true);

CREATE TABLE IF NOT EXISTS public.incident_types (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name TEXT NOT NULL, description TEXT
);
ALTER TABLE public.incident_types ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public Read Incident Types" ON public.incident_types FOR SELECT USING (true);

CREATE TABLE IF NOT EXISTS public.incidents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    reported_by_user_id UUID REFERENCES auth.users(id),
    incident_type_id UUID REFERENCES incident_types(id),
    date_reported TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    date_occurred TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    location TEXT, description TEXT, immediate_action TEXT,
    status TEXT DEFAULT 'Pending' CHECK (status IN ('Pending', 'Investigating', 'Resolved', 'Closed'))
);
ALTER TABLE public.incidents ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public All Incidents" ON public.incidents FOR ALL USING (true) WITH CHECK (true);

-- 3. Additional Support Tables
CREATE TABLE IF NOT EXISTS public.interventions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    assigned_by_user_id UUID REFERENCES auth.users(id),
    intervention_type TEXT, description TEXT, status TEXT DEFAULT 'Active',
    start_date TIMESTAMP WITH TIME ZONE DEFAULT NOW(), end_date TIMESTAMP WITH TIME ZONE
);
CREATE TABLE IF NOT EXISTS public.device_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    activity_description TEXT, flagged BOOLEAN DEFAULT FALSE,
    usage_start TIMESTAMP WITH TIME ZONE DEFAULT NOW(), usage_end TIMESTAMP WITH TIME ZONE
);
CREATE TABLE IF NOT EXISTS public.parents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    first_name TEXT, last_name TEXT, relationship_to_student TEXT,
    contact_number TEXT, email TEXT, address TEXT
);
CREATE TABLE IF NOT EXISTS public.generated_reports (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    title TEXT, type TEXT, generated_by_user_id UUID REFERENCES auth.users(id),
    status TEXT DEFAULT 'Ready', file_size TEXT, date_generated TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS public.system_audit_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    user_name TEXT, action TEXT, category TEXT, ip_address TEXT,
    timestamp TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS public.notifications (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    title TEXT, message TEXT, type TEXT, is_read BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Grant Access to All Roles
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, service_role;
    `.trim();
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateSql());
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });

      if (authError) {
        if (authError.message.includes('Email not confirmed')) {
          throw new Error('Email Confirmation is ACTIVE in Supabase. Disable it in Auth > Settings > Provider Settings to log in instantly.');
        }
        throw authError;
      }

      if (authData.user) {
        // Fetch or create profile (Resilient Auto-Heal)
        const { data: profile, error: profError } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', authData.user.id)
          .single();

        if (profError) {
          console.warn("Profile missing for authenticated user. Healing...");
          const { data: newProfile, error: healError } = await supabase.from('profiles').upsert([{
            id: authData.user.id,
            username: email.split('@')[0],
            full_name: authData.user.user_metadata?.full_name || 'Restored User',
            role: authData.user.user_metadata?.role || 'Teacher',
            is_active: true
          }]).select().single();

          if (healError) {
            console.error("Heal Error:", healError);
            throw new Error(`DB SYNC ERROR: ${healError.message}. This usually means the "profiles" table is missing RLS policies. Please run the SQL Fix script.`);
          }
          onLogin(newProfile);
        } else {
          onLogin(profile);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Invalid credentials or database connection failed.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        let userId = authData?.user?.id;

        if (signUpError?.message?.includes('already registered')) {
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email: account.email,
            password: account.password
          });
          if (signInError) throw signInError;
          userId = signInData.user?.id;
        } else if (signUpError) {
          throw signUpError;
        }

        if (userId) {
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: userId,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;

          setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
            ...s, 
            status: signUpError ? 'healed' : 'success' 
          } : s));
        }

        await supabase.auth.signOut();
      } catch (err: any) {
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
          ...s, 
          status: 'error', 
          message: err.message 
        } : s));
      }
    }
    checkDatabase();
  };

  const quickAccess = (targetEmail: string) => {
    setEmail(targetEmail);
    setPassword('12345678');
    setIsLoginMode(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">

        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden transition-all duration-500">
          {/* Diagnostic Header */}
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between border-b border-white/5">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${
                dbStatus === 'online' ? 'bg-teal-400 shadow-[0_0_8px_rgba(45,212,191,0.6)]' : 
                dbStatus === 'checking' ? 'bg-amber-400 animate-pulse' : 
                'bg-red-500'
              }`}></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">
                {dbStatus === 'online' ? 'Supabase Synced' : 
                 dbStatus === 'checking' ? 'Establishing Link...' : 
                 dbStatus === 'missing_tables' ? 'Repair Required' : 'Offline'}
              </span>
            </div>
            <button onClick={checkDatabase} className="text-white/40 hover:text-white transition-colors">
              <Terminal size={12} />
            </button>
          </div>

          {/* Critical Schema Warning */}
          {dbStatus === 'missing_tables' && !showSql && (
            <div className="p-5 bg-amber-50 border-b border-amber-100 flex items-start gap-3 animate-in slide-in-from-top-4">
              <div className="w-10 h-10 bg-amber-100 rounded-lg flex items-center justify-center text-amber-600 shrink-0">
                <DatabaseZap size={20} />
              </div>
              <div className="flex-1">
                <p className="text-[11px] font-black text-amber-900 uppercase tracking-tight">Database Schema Missing</p>
                <p className="text-[10px] text-amber-700 mt-1 font-medium leading-relaxed">Required tables or RLS policies were not found in your Supabase project.</p>
                <div className="flex gap-2 mt-3">
                  <button 
                    onClick={() => setShowSql(true)}
                    className="text-[9px] font-black text-white bg-amber-600 px-3 py-1.5 rounded-lg hover:bg-amber-700 transition-all flex items-center gap-1.5"
                  >
                    <Code size={12} /> Get SQL Fix
                  </button>
                  <button 
                    onClick={checkDatabase}
                    className="text-[9px] font-black text-amber-600 bg-white border border-amber-200 px-3 py-1.5 rounded-lg hover:bg-amber-50 transition-all"
                  >
                    Re-Check
                  </button>
                </div>
              </div>
            </div>
          )}

          {showSql ? (
            <div className="p-8 bg-slate-900 text-teal-400 space-y-5 animate-in fade-in zoom-in-95">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <Terminal size={16} className="text-teal-400" />
                  <h3 className="text-[10px] font-black uppercase tracking-widest text-white/70">SQL Fix Script</h3>
                </div>
                <button onClick={() => setShowSql(false)} className="text-white/40 hover:text-white"><X size={16} /></button>
              </div>
              <p className="text-[10px] text-white/50 leading-relaxed italic">
                Paste this into your <strong>Supabase SQL Editor</strong> and click "Run". This will create all tables and apply permissive RLS policies.
              </p>
              <div className="bg-black/40 p-5 rounded-xl border border-white/5 font-mono text-[9px] overflow-x-auto max-h-48 whitespace-pre text-teal-300 custom-scrollbar shadow-inner">
                {generateSql()}
              </div>
              <button 
                onClick={copyToClipboard}
                className="w-full flex items-center justify-center gap-2 py-4 bg-teal-500 text-slate-900 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-teal-400 transition-all active:scale-95 shadow-xl shadow-teal-500/20"
              >
                {copySuccess ? <CheckCircle size={14} /> : <Copy size={14} />}
                {copySuccess ? 'Copied to Clipboard' : 'Copy SQL Repair Script'}
              </button>
            </div>
          ) : isSeeding ? (
            <div className="p-8 space-y-4 animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center gap-2 mb-2">
                <Zap size={14} className="text-amber-500 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Syncing Registry...</span>
              </div>
              <div className="space-y-3">
                {seedStep.map((step, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{step.email}</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{step.role}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      {step.status === 'loading' && <Loader2 size={16} className="text-teal-600 animate-spin" />}
                      {step.status === 'success' && <CheckCircle2 size={16} className="text-teal-600" />}
                      {step.status === 'healed' && <div className="text-[9px] font-black uppercase bg-blue-50 text-blue-700 px-2 py-1 rounded">Synced</div>}
                      {step.status === 'error' && <AlertCircle size={16} className="text-red-500" />}
                      {step.status === 'pending' && <div className="w-4 h-4 rounded-full border border-slate-200"></div>}
                    </div>
                  </div>
                ))}
              </div>
              <button onClick={() => setIsSeeding(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl">
                Return to Login
              </button>
            </div>
          ) : (
            <>
              <div className="p-10 pb-6 text-center">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl border border-slate-700 ring-4 ring-slate-50">
                  <ShieldCheck size={32} />
                </div>
                <h1 className="text-3xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
                <p className="text-slate-500 mt-2 text-xs font-medium uppercase tracking-widest">Secure Educational Registry</p>
              </div>

              <div className="px-10 flex border-b border-slate-100">
                <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign In</button>
                <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign Up</button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 pt-8 space-y-4">
                {error && (
                  <div className="p-4 bg-red-50 border border-red-100 rounded-xl text-red-900 text-[10px] font-bold uppercase tracking-tight flex items-start gap-3 animate-in slide-in-from-top-1">
                    <AlertCircle size={16} className="text-red-600 shrink-0 mt-0.5" />
                    <span>{error}</span>
                  </div>
                )}

                <div className="space-y-4">
                  {!isLoginMode && (
                    <div className="space-y-4 animate-in fade-in duration-300">
                      <div className="relative">
                        <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-1 focus:ring-slate-900 outline-none transition-all" placeholder="Full Name" />
                      </div>
                      <div className="relative">
                        <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <select value={role} onChange={(e) => setRole(e.target.value as any)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm appearance-none focus:ring-1 focus:ring-slate-900 outline-none transition-all">
                          <option value="Teacher">Teacher</option>
                          <option value="Counselor">Counselor</option>
                          <option value="Administrator">Administrator</option>
                        </select>
                      </div>
                    </div>
                  )}
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-1 focus:ring-slate-900 outline-none transition-all" placeholder="Official Email" />
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-1 focus:ring-slate-900 outline-none transition-all" placeholder="Password" />
                  </div>
                </div>

                <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-2xl active:scale-[0.98] disabled:opacity-70 disabled:active:scale-100">
                  {isLoading ? <Loader2 size={18} className="animate-spin mx-auto" /> : isLoginMode ? 'Verify Access' : 'Create Registry ID'}
                </button>
              </form>

              {isLoginMode && (
                <div className="px-10 pb-10 space-y-6">
                  <div className="relative">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
                    <div className="relative flex justify-center text-[9px] uppercase font-black tracking-widest"><span className="bg-white px-4 text-slate-400">Quick Portal Access</span></div>
                  </div>

                  <div className="grid grid-cols-3 gap-2">
                    {['teacher', 'counselor', 'admin'].map(type => (
                      <button key={type} onClick={() => quickAccess(`${type}@gmail.com`)} className="py-2.5 border border-slate-200 rounded-xl text-[9px] font-black uppercase tracking-tighter hover:bg-slate-50 text-slate-600 transition-all active:bg-slate-100">{type}</button>
                    ))}
                  </div>

                  <div className="space-y-3">
                    <button onClick={handleInitializeDemo} className="w-full flex items-center justify-between px-5 py-4 bg-teal-50 text-teal-700 border border-teal-100 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-teal-100 transition-all group">
                      <div className="flex items-center gap-2">
                        <Database size={14} className="group-hover:rotate-12 transition-transform" />
                        Initialize / Repair Connection
                      </div>
                      <ChevronRight size={14} />
                    </button>
                    <div className="flex items-center justify-center gap-3 text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                      <span className="flex items-center gap-1"><Info size={10} /> Password: 12345678</span>
                    </div>
                  </div>
                </div>
              )}
            </>
          )}
        </div>

        <p className="text-slate-400 text-[9px] text-center uppercase tracking-widest font-black flex items-center justify-center gap-2 mb-8">
          <Shield size={10} className="text-teal-600" /> Authorized Educational Portal • System Integrity Level High
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, 
  Briefcase, Database, CheckCircle2, Loader2, Info, Terminal, 
  ChevronRight, Settings, Copy, Code, AlertTriangle, X, CheckCircle,
  Zap, DatabaseZap
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'healed' | 'error';
  message?: string;
}

const REQUIRED_TABLES = [
  'profiles', 'students', 'incidents', 'incident_types', 
  'interventions', 'device_logs', 'parents', 
  'generated_reports', 'system_audit_logs', 'notifications'
];

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSql, setShowSql] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);

  // Connectivity Stats
  const [missingTables, setMissingTables] = useState<string[]>([]);
  const [dbStatus, setDbStatus] = useState<'checking' | 'online' | 'missing_tables' | 'offline'>('checking');

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  useEffect(() => {
    checkDatabase();
  }, []);

  const checkDatabase = async () => {
    setDbStatus('checking');
    const missing: string[] = [];

    try {
      for (const table of REQUIRED_TABLES) {
        const { error } = await supabase.from(table).select('id').limit(1);
        // Error code 42P01 is Postgres for "table does not exist"
        if (error && (error.code === '42P01' || error.message.includes('does not exist'))) {
          missing.push(table);
        }
      }

      if (missing.length > 0) {
        setMissingTables(missing);
        setDbStatus('missing_tables');
      } else {
        setDbStatus('online');
      }
    } catch (e) {
      setDbStatus('offline');
    }
  };

  const generateSql = () => {
    return `
-- ==========================================
-- SAFE-EDU EMERGENCY SCHEMA & RLS REPAIR
-- ==========================================

-- 1. Profiles (Linked to Auth)
CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    username TEXT UNIQUE,
    full_name TEXT,
    role TEXT CHECK (role IN ('Teacher', 'Counselor', 'Administrator')),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- FIX RLS FOR PROFILES (CRITICAL: Fixes 'violates row-level security policy' error)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public All" ON public.profiles;
CREATE POLICY "Public All" ON public.profiles FOR ALL USING (true) WITH CHECK (true);

-- 2. Core Operational Tables
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    lrn TEXT UNIQUE NOT NULL,
    first_name TEXT, last_name TEXT, date_of_birth DATE,
    gender TEXT, grade_level TEXT, section TEXT, address TEXT, contact_number TEXT
);
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public All Students" ON public.students;
CREATE POLICY "Public All Students" ON public.students FOR ALL USING (true) WITH CHECK (true);

CREATE TABLE IF NOT EXISTS public.incident_types (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name TEXT NOT NULL, description TEXT
);
ALTER TABLE public.incident_types ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Read Incident Types" ON public.incident_types;
CREATE POLICY "Public Read Incident Types" ON public.incident_types FOR SELECT USING (true);

CREATE TABLE IF NOT EXISTS public.incidents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    reported_by_user_id UUID REFERENCES auth.users(id),
    incident_type_id UUID REFERENCES incident_types(id),
    date_reported TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    date_occurred TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    location TEXT, description TEXT, immediate_action TEXT,
    status TEXT DEFAULT 'Pending' CHECK (status IN ('Pending', 'Investigating', 'Resolved', 'Closed'))
);
ALTER TABLE public.incidents ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public All Incidents" ON public.incidents;
CREATE POLICY "Public All Incidents" ON public.incidents FOR ALL USING (true) WITH CHECK (true);

CREATE TABLE IF NOT EXISTS public.interventions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    assigned_by_user_id UUID REFERENCES auth.users(id),
    intervention_type TEXT, description TEXT, status TEXT DEFAULT 'Active',
    start_date TIMESTAMP WITH TIME ZONE DEFAULT NOW(), end_date TIMESTAMP WITH TIME ZONE
);
ALTER TABLE public.interventions ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public All Interventions" ON public.interventions FOR ALL USING (true) WITH CHECK (true);

