GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, service_role;
    `.trim();
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateSql());
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });

        if (authError) {
          if (authError.message.includes('Email not confirmed')) {
            throw new Error('Email Confirmation is ACTIVE. Disable it in Supabase Auth > Settings.');
          }
          throw authError;
        }

        if (authData.user) {
          const { data: profile, error: profError } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', authData.user.id)
            .single();

          if (profError) {
            console.warn("Profile missing. Healing...");
            const { data: newProfile, error: healError } = await supabase.from('profiles').upsert([{
              id: authData.user.id,
              username: email.split('@')[0],
              full_name: authData.user.user_metadata?.full_name || 'Restored User',
              role: authData.user.user_metadata?.role || 'Teacher',
              is_active: true
            }]).select().single();

            if (healError) throw healError;
            onLogin(newProfile);
          } else {
            onLogin(profile);
          }
        }
      } else {
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, role: role } }
        });

        if (signUpError) throw signUpError;

        if (signUpData.user) {
          const { data: profile, error: profError } = await supabase.from('profiles').insert([{
            id: signUpData.user.id,
            username: email.split('@')[0],
            full_name: fullName,
            role: role,
            is_active: true
          }]).select().single();

          if (profError) throw profError;
          onLogin(profile);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Database connection error.');
      if (err.message.includes('row-level security policy')) {
        setShowSql(true);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        let userId = authData?.user?.id;

        if (signUpError?.message?.includes('already registered')) {
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email: account.email,
            password: account.password
          });
          if (signInError) throw signInError;
          userId = signInData.user?.id;
        } else if (signUpError) {
          throw signUpError;
        }

        if (userId) {
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: userId,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;

          setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
            ...s, 
            status: 'success' 
          } : s));
        }

        await supabase.auth.signOut();
      } catch (err: any) {
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { 
          ...s, 
          status: 'error', 
          message: err.message 
        } : s));
      }
    }
    checkDatabase();
  };

  const quickAccess = (targetEmail: string) => {
    setEmail(targetEmail);
    setPassword('12345678');
    setIsLoginMode(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          {/* Diagnostic Header */}
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${
                dbStatus === 'online' ? 'bg-teal-400' : 'bg-red-500'
              }`}></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">
                {dbStatus === 'online' ? 'Supabase Synced' : 'Action Required'}
              </span>
            </div>
            <button onClick={checkDatabase} className="text-white/40 hover:text-white"><Terminal size={12} /></button>
          </div>

          {dbStatus === 'missing_tables' && !showSql && (
            <div className="p-5 bg-amber-50 border-b border-amber-100 flex items-start gap-3">
              <div className="w-10 h-10 bg-amber-100 rounded-lg flex items-center justify-center text-amber-600 shrink-0">
                <DatabaseZap size={20} />
              </div>
              <div className="flex-1">
                <p className="text-[11px] font-black text-amber-900 uppercase">Schema Mismatch</p>
                <p className="text-[10px] text-amber-700 mt-1">Missing: {missingTables.join(', ')}</p>
                <button onClick={() => setShowSql(true)} className="mt-2 text-[9px] font-black text-white bg-amber-600 px-3 py-1.5 rounded-lg flex items-center gap-1">
                  <Code size={12} /> Fix Now
                </button>
              </div>
            </div>
          )}

          {showSql ? (
            <div className="p-8 bg-slate-900 text-teal-400 space-y-4">
              <div className="flex justify-between items-center">
                <h3 className="text-[10px] font-black uppercase tracking-widest text-white/70">SQL Fix Script</h3>
                <button onClick={() => setShowSql(false)} className="text-white/40"><X size={16} /></button>
              </div>
              <div className="bg-black/40 p-4 rounded-xl font-mono text-[9px] overflow-auto max-h-48 whitespace-pre text-teal-300">
                {generateSql()}
              </div>
              <button onClick={copyToClipboard} className="w-full py-4 bg-teal-500 text-slate-900 rounded-xl font-black text-[10px] uppercase shadow-xl">
                {copySuccess ? 'Copied' : 'Copy Fix Script'}
              </button>
            </div>
          ) : isSeeding ? (
            <div className="p-8 space-y-4">
              <h3 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Seeding Registry...</h3>
              {seedStep.map((step, idx) => (
                <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-900">{step.email}</span>
                  {step.status === 'loading' ? <Loader2 size={16} className="animate-spin text-teal-600" /> : <CheckCircle2 size={16} className="text-teal-600" />}
                </div>
              ))}
              <button onClick={() => setIsSeeding(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-xs uppercase">Done</button>
            </div>
          ) : (
            <>
              <div className="p-10 pb-6 text-center">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl">
                  <ShieldCheck size={32} />
                </div>
                <h1 className="text-3xl font-bold text-slate-900">SAFE-EDU</h1>
                <p className="text-slate-500 mt-2 text-[10px] font-black uppercase tracking-widest">Secure Student Registry</p>
              </div>

              <div className="px-10 flex border-b border-slate-100">
                <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign In</button>
                <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400'}`}>Sign Up</button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 space-y-4">
                {error && <div className="p-3 bg-red-50 text-red-900 text-[10px] font-bold uppercase rounded-lg border border-red-100">{error}</div>}
                <div className="space-y-4">
                  {!isLoginMode && (
                    <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm" placeholder="Full Name" />
                  )}
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm" placeholder="Official Email" />
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm" placeholder="Password" />
                  </div>
                </div>
                <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase shadow-2xl">
                  {isLoading ? <Loader2 className="animate-spin mx-auto" /> : 'Enter Portal'}
                </button>
              </form>

              <div className="px-10 pb-10 space-y-6">
                <div className="grid grid-cols-3 gap-2">
                  {['teacher', 'counselor', 'admin'].map(type => (
                    <button key={type} onClick={() => quickAccess(`${type}@gmail.com`)} className="py-2 border border-slate-200 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50">{type}</button>
                  ))}
                </div>
                <button onClick={handleInitializeDemo} className="w-full py-4 bg-teal-50 text-teal-700 border border-teal-100 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2">
                  <Database size={14} /> Repair / Init Demo Accounts
                </button>
              </div>
            </>
          )}
        </div>
        <p className="text-slate-400 text-[9px] text-center uppercase tracking-widest font-black flex items-center justify-center gap-2">
          <Shield size={10} className="text-teal-600" /> Secure Educational Environment
        </p>
      </div>
    </div>
  );
};

