        </div>
        <p className="text-slate-400 text-[9px] text-center uppercase tracking-widest font-black flex items-center justify-center gap-2">
          <Shield size={10} className="text-teal-600" /> Authorized Educational Portal • Registry System v2.1
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, 
  Briefcase, Database, CheckCircle2, Loader2, Info, Terminal, 
  ChevronRight, DatabaseZap, Copy, Code, X, CheckCircle, Zap, AlertTriangle
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'healed' | 'error';
  message?: string;
}

const REQUIRED_TABLES = [
  'profiles', 'students', 'incidents', 'incident_types', 
  'interventions', 'device_logs', 'parents', 
  'generated_reports', 'system_audit_logs', 'notifications'
];

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSql, setShowSql] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);

  // Connectivity Stats
  const [missingTables, setMissingTables] = useState<string[]>([]);
  const [dbStatus, setDbStatus] = useState<'checking' | 'online' | 'missing_tables' | 'offline'>('checking');

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  useEffect(() => {
    checkDatabase();
  }, []);

  const checkDatabase = async () => {
    setDbStatus('checking');
    const missing: string[] = [];

    try {
      for (const table of REQUIRED_TABLES) {
        const { error } = await supabase.from(table).select('id').limit(1);
        if (error && (error.code === '42P01' || error.message.includes('does not exist'))) {
          missing.push(table);
        }
      }

      if (missing.length > 0) {
        setMissingTables(missing);
        setDbStatus('missing_tables');
      } else {
        setDbStatus('online');
      }
    } catch (e) {
      setDbStatus('offline');
    }
  };

  const generateSql = () => {
    return `
-- ======================================================
-- SAFE-EDU SUPABASE EMERGENCY REPAIR SCRIPT
-- ======================================================

-- 1. DROP EXISTING POLICIES TO PREVENT CONFLICTS
DROP POLICY IF EXISTS "Public Full Access" ON public.profiles;
DROP POLICY IF EXISTS "Public All" ON public.profiles;

-- 2. ENSURE PROFILES TABLE EXISTS
CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    username TEXT UNIQUE,
    full_name TEXT,
    role TEXT CHECK (role IN ('Teacher', 'Counselor', 'Administrator')),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 3. BYPASS RLS RESTRICTIONS (The "Fix-Everything" Step)
-- Option A: Completely disable RLS for simplicity in development
ALTER TABLE public.profiles DISABLE ROW LEVEL SECURITY;

-- Option B: If you prefer RLS enabled, run this permissive policy:
-- ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
-- CREATE POLICY "Public Full Access" ON public.profiles FOR ALL USING (true) WITH CHECK (true);

-- 4. ENSURE OTHER TABLES EXIST
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    lrn TEXT UNIQUE NOT NULL,
    first_name TEXT, last_name TEXT, date_of_birth DATE,
    gender TEXT, grade_level TEXT, section TEXT, address TEXT, contact_number TEXT
);
ALTER TABLE public.students DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.incident_types (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name TEXT NOT NULL, description TEXT
);
ALTER TABLE public.incident_types DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.incidents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    reported_by_user_id UUID REFERENCES auth.users(id),
    incident_type_id UUID REFERENCES incident_types(id),
    date_reported TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    date_occurred TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    location TEXT, description TEXT, immediate_action TEXT,
    status TEXT DEFAULT 'Pending' CHECK (status IN ('Pending', 'Investigating', 'Resolved', 'Closed'))
);
ALTER TABLE public.incidents DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.interventions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    assigned_by_user_id UUID REFERENCES auth.users(id),
    intervention_type TEXT, description TEXT, status TEXT DEFAULT 'Active',
    start_date TIMESTAMP WITH TIME ZONE DEFAULT NOW(), end_date TIMESTAMP WITH TIME ZONE
);
ALTER TABLE public.interventions DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.device_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    activity_description TEXT, flagged BOOLEAN DEFAULT FALSE,
    usage_start TIMESTAMP WITH TIME ZONE DEFAULT NOW(), usage_end TIMESTAMP WITH TIME ZONE
);
ALTER TABLE public.device_logs DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.parents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    first_name TEXT, last_name TEXT, relationship_to_student TEXT,
    contact_number TEXT, email TEXT, address TEXT
);
ALTER TABLE public.parents DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.generated_reports (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    title TEXT, type TEXT, generated_by_user_id UUID REFERENCES auth.users(id),
    status TEXT DEFAULT 'Ready', file_size TEXT, date_generated TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.generated_reports DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.system_audit_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    user_name TEXT, action TEXT, category TEXT, ip_address TEXT,
    timestamp TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.system_audit_logs DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.notifications (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    title TEXT, message TEXT, type TEXT, is_read BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.notifications DISABLE ROW LEVEL SECURITY;

-- 5. RE-GRANT PERMISSIONS
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL FUNCTIONS IN SCHEMA public TO anon, authenticated, service_role;
    `.trim();
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateSql());
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;

        if (authData.user) {
          const { data: profile, error: profError } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', authData.user.id)
            .single();

          if (profError) {
            console.warn("Profile missing. Attempting restoration...");
            const { data: healedProfile, error: healError } = await supabase.from('profiles').upsert([{
              id: authData.user.id,
              username: email.split('@')[0],
              full_name: authData.user.user_metadata?.full_name || 'Restored User',
              role: authData.user.user_metadata?.role || 'Teacher',
              is_active: true
            }]).select().single();

            if (healError) {
              if (healError.message.toLowerCase().includes('row-level security') || healError.message.toLowerCase().includes('rls')) {
                throw new Error("DB Security Breach: RLS prevents profile creation. Please run the 'SQL Fix' script in your Supabase console.");
              }
              throw healError;
            }
            onLogin(healedProfile);
          } else {
            onLogin(profile);
          }
        }
      } else {
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, role: role } }
        });

        if (signUpError) throw signUpError;

        if (signUpData.user) {
          const { data: profile, error: profError } = await supabase.from('profiles').insert([{
            id: signUpData.user.id,
            username: email.split('@')[0],
            full_name: fullName,
            role: role,
            is_active: true
          }]).select().single();

          if (profError) {
             if (profError.message.toLowerCase().includes('row-level security') || profError.message.toLowerCase().includes('rls')) {
                throw new Error("RLS Violation: Database policy blocked profile creation. Click 'Get SQL Fix' below.");
              }
            throw profError;
          }
          onLogin(profile);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Identity verification failed.');
      if (err.message.toLowerCase().includes('row-level security') || err.message.toLowerCase().includes('rls')) {
        setShowSql(true);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        let userId = authData?.user?.id;

        if (signUpError?.message?.includes('already registered')) {
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email: account.email,
            password: account.password
          });
          if (signInError) throw signInError;
          userId = signInData.user?.id;
        } else if (signUpError) {
          throw signUpError;
        }

        if (userId) {
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: userId,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;

          setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'success' } : s));
        }

        await supabase.auth.signOut();
      } catch (err: any) {
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'error', message: err.message } : s));
      }
    }
    checkDatabase();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          {/* Status Header */}
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${dbStatus === 'online' ? 'bg-teal-400 shadow-[0_0_8px_rgba(45,212,191,0.5)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)] animate-pulse'}`}></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">
                {dbStatus === 'online' ? 'Supabase Synced' : 'Database Error Detected'}
              </span>
            </div>
            <button onClick={checkDatabase} title="Check Connectivity" className="text-white/40 hover:text-white transition-colors">
              <Terminal size={12} />
            </button>
          </div>

          {showSql ? (
            <div className="p-8 bg-slate-900 text-teal-400 space-y-5 animate-in zoom-in-95 duration-300">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-2 text-white/70">
                  <Terminal size={16} />
                  <h3 className="text-[10px] font-black uppercase tracking-widest">Emergency Repair Script</h3>
                </div>
                <button onClick={() => setShowSql(false)} className="text-white/40 hover:text-white"><X size={16} /></button>
              </div>
              <p className="text-[10px] text-white/50 leading-relaxed">
                The error you saw (RLS Violation) is a Supabase security setting. 
                Paste the script below into your <strong>Supabase SQL Editor</strong> and click <strong>Run</strong>. 
