              </p>
              <div className="bg-black/40 p-5 rounded-xl border border-white/5 font-mono text-[9px] overflow-x-auto max-h-48 whitespace-pre text-teal-300 custom-scrollbar">
                {generateSql()}
              </div>
              <button 
                onClick={copyToClipboard}
                className="w-full py-4 bg-teal-500 text-slate-900 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-teal-400 transition-all shadow-xl active:scale-95"
              >
                {copySuccess ? 'Success: Script Copied' : 'Copy Emergency Fix Script'}
              </button>
            </div>
          ) : isSeeding ? (
            <div className="p-8 space-y-4 animate-in fade-in">
              <div className="flex items-center gap-2 mb-2">
                <Zap size={14} className="text-amber-500 animate-pulse" />
                <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Registry Syncing...</span>
              </div>
              <div className="space-y-2">
                {seedStep.map((step, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{step.email}</span>
                      <span className="text-[9px] text-slate-400 font-bold uppercase">{step.role}</span>
                    </div>
                    {step.status === 'loading' ? (
                      <Loader2 size={16} className="animate-spin text-teal-600" />
                    ) : step.status === 'success' ? (
                      <CheckCircle2 size={16} className="text-teal-600" />
                    ) : step.status === 'error' ? (
                      <AlertCircle size={16} className="text-red-500" />
                    ) : (
