                  ))}
                </div>
                <button onClick={handleInitializeDemo} className="w-full py-4 bg-teal-50 text-teal-700 border border-teal-100 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2 hover:bg-teal-100 transition-all">
                  <Database size={14} /> Repair / Initialize Demo Data
                </button>
              </div>
            </>
          )}
        </div>
        <p className="text-slate-400 text-[9px] text-center uppercase tracking-widest font-black flex items-center justify-center gap-2">
          <Shield size={10} className="text-teal-600" /> Secure Educational Portal • Version 2.4-STABLE
        </p>
      </div>
    </div>
  );
};

export default Login;

