import { GoogleGenAI, Type } from "@google/genai";

/**
 * Analyze student behavioral history using Gemini 3 Pro.
 * Utilizes the new thinkingBudget to allow the model more reasoning time 
 * for complex behavioral pattern recognition in educational settings.
 */
export const getBehavioralInsight = async (studentHistory: any[]) => {
  // Initialize right before use to ensure the latest API key context
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an expert educational psychologist and behavioral analyst. 
    Analyze the following student incident history and provide a professional, 
    constructive assessment. Focus on identifying triggers, patterns, and 
    positive growth opportunities.

    Student Incident Data:
    ${JSON.stringify(studentHistory)}

    Format your response as a JSON object that adheres to the provided schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        // Behavioral analysis benefits from deeper reasoning time
        thinkingConfig: { thinkingBudget: 2048 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { 
              type: Type.STRING, 
              description: "Professional psych-educational analysis of the behavior patterns observed." 
            },
            riskLevel: { 
              type: Type.STRING, 
              description: "Assessment of risk (Low, Medium, High) for future behavioral escalations." 
            },
            suggestedInterventions: {
              type: Type.ARRAY,
              description: "Actionable, evidence-based strategies for teachers and counselors.",
              items: { type: Type.STRING }
            },
            growthFocus: {
              type: Type.STRING,
              description: "A specific area of focus for the student's personal development and positive reinforcement."
            }
          },
          required: ["analysis", "riskLevel", "suggestedInterventions", "growthFocus"]
        }
      }
    });

    // Directly access the .text property from the GenerateContentResponse object
    const resultText = response.text || "{}";
    return JSON.parse(resultText);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return {
      analysis: "Automated analysis encountered an error. Please manually review the case logs to determine if further intervention is required.",
      riskLevel: "Undetermined",
      suggestedInterventions: [
        "Schedule a primary consultation with the student.",
        "Verify parental contact details for notification.",
        "Review digital safety logs for related flags."
      ],
      growthFocus: "General self-regulation and peer communication."
    };
  }
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, AlertCircle, Shield, User as UserIcon, 
  Briefcase, Database, CheckCircle2, Loader2, Info, Terminal, 
  ChevronRight, DatabaseZap, Copy, Code, X, CheckCircle, Zap, AlertTriangle,
  ExternalLink, ServerCrash
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
}

interface SeedStatus {
  email: string;
  role: string;
  status: 'pending' | 'loading' | 'success' | 'healed' | 'error';
  message?: string;
}

const REQUIRED_TABLES = [
  'profiles', 'students', 'incidents', 'incident_types', 
  'interventions', 'device_logs', 'parents', 
  'generated_reports', 'system_audit_logs', 'notifications'
];

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Administrator'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSql, setShowSql] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);

  // Connectivity Stats
  const [missingTables, setMissingTables] = useState<string[]>([]);
  const [dbStatus, setDbStatus] = useState<'checking' | 'online' | 'missing_tables' | 'rls_blocked' | 'offline'>('checking');

  // Seeding States
  const [isSeeding, setIsSeeding] = useState(false);
  const [seedStep, setSeedStep] = useState<SeedStatus[]>([]);

  useEffect(() => {
    checkDatabase();
  }, []);

  const checkDatabase = async () => {
    setDbStatus('checking');
    const missing: string[] = [];
    let rlsIssue = false;

    try {
      // Test profiles specifically for RLS issues
      const { error: profError } = await supabase.from('profiles').select('id').limit(1);
      if (profError) {
        if (profError.message.includes('row-level security') || profError.code === '42501') {
          rlsIssue = true;
        } else if (profError.code === '42P01') {
          missing.push('profiles');
        }
      }

      for (const table of REQUIRED_TABLES) {
        if (table === 'profiles') continue;
        const { error } = await supabase.from(table).select('id').limit(1);
        if (error && (error.code === '42P01' || error.message.includes('does not exist'))) {
          missing.push(table);
        }
      }

      if (rlsIssue) {
        setDbStatus('rls_blocked');
      } else if (missing.length > 0) {
        setMissingTables(missing);
        setDbStatus('missing_tables');
      } else {
        setDbStatus('online');
      }
    } catch (e) {
      setDbStatus('offline');
    }
  };

  const generateSql = () => {
    return `
-- ======================================================
-- SAFE-EDU SUPABASE "NUCLEAR" REPAIR SCRIPT
-- Run this in your Supabase SQL Editor (SQL Tools > New Query)
-- ======================================================

-- 1. CLEANUP & SCHEMA SETUP
DROP POLICY IF EXISTS "Public Full Access" ON public.profiles;
DROP POLICY IF EXISTS "Public All" ON public.profiles;

CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    username TEXT UNIQUE,
    full_name TEXT,
    role TEXT CHECK (role IN ('Teacher', 'Counselor', 'Administrator')),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. DISABLE RLS (Simplest fix for 'violations row-level security policy')
ALTER TABLE public.profiles DISABLE ROW LEVEL SECURITY;

-- 3. ENSURE ALL CORE TABLES EXIST & BYPASS SECURITY
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    lrn TEXT UNIQUE NOT NULL,
    first_name TEXT, last_name TEXT, date_of_birth DATE,
    gender TEXT, grade_level TEXT, section TEXT, address TEXT, contact_number TEXT
);
ALTER TABLE public.students DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.incident_types (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name TEXT NOT NULL, description TEXT
);
ALTER TABLE public.incident_types DISABLE ROW LEVEL SECURITY;

-- SEED INCIDENT TYPES
INSERT INTO public.incident_types (name, description) VALUES
('Bullying', 'Repeated harmful behavior towards a peer.'),
('Academic Dishonesty', 'Cheating or plagiarism.'),
('Property Damage', 'Vandalism to school property.'),
('Digital Misuse', 'Unauthorized access on school devices.'),
('Verbal Altercation', 'Heated argument involving inappropriate language.')
ON CONFLICT DO NOTHING;

CREATE TABLE IF NOT EXISTS public.incidents (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    reported_by_user_id UUID REFERENCES auth.users(id),
    incident_type_id UUID REFERENCES incident_types(id),
    date_reported TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    date_occurred TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    location TEXT, description TEXT, immediate_action TEXT,
    status TEXT DEFAULT 'Pending' CHECK (status IN ('Pending', 'Investigating', 'Resolved', 'Closed'))
);
ALTER TABLE public.incidents DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.interventions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    assigned_by_user_id UUID REFERENCES auth.users(id),
    intervention_type TEXT, description TEXT, status TEXT DEFAULT 'Active',
    start_date TIMESTAMP WITH TIME ZONE DEFAULT NOW(), end_date TIMESTAMP WITH TIME ZONE
);
ALTER TABLE public.interventions DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.device_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES students(id),
    activity_description TEXT, flagged BOOLEAN DEFAULT FALSE,
    usage_start TIMESTAMP WITH TIME ZONE DEFAULT NOW(), usage_end TIMESTAMP WITH TIME ZONE
);
ALTER TABLE public.device_logs DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.parents (
