    timestamp TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.system_audit_logs DISABLE ROW LEVEL SECURITY;

CREATE TABLE IF NOT EXISTS public.notifications (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    title TEXT, message TEXT, type TEXT, is_read BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
ALTER TABLE public.notifications DISABLE ROW LEVEL SECURITY;

-- 4. FINAL PERMISSIONS RE-GRANT
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON ALL FUNCTIONS IN SCHEMA public TO anon, authenticated, service_role;
    `.trim();
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generateSql());
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;

        if (authData.user) {
          const { data: profile, error: profError } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', authData.user.id)
            .single();

          if (profError) {
            console.warn("Profile missing. Attempting restoration...");
            const { data: healedProfile, error: healError } = await supabase.from('profiles').upsert([{
              id: authData.user.id,
              username: email.split('@')[0],
              full_name: authData.user.user_metadata?.full_name || 'Restored User',
              role: authData.user.user_metadata?.role || 'Teacher',
              is_active: true
            }]).select().single();

            if (healError) {
              if (healError.message.toLowerCase().includes('security') || healError.message.toLowerCase().includes('rls')) {
                throw new Error("DB SYNC ERROR: Row-level security policy prevents profile creation. Run SQL Fix script.");
              }
              throw healError;
            }
            onLogin(healedProfile);
          } else {
            onLogin(profile);
          }
        }
      } else {
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { data: { full_name: fullName, role: role } }
        });

        if (signUpError) throw signUpError;

        if (signUpData.user) {
          const { data: profile, error: profError } = await supabase.from('profiles').insert([{
            id: signUpData.user.id,
            username: email.split('@')[0],
            full_name: fullName,
            role: role,
            is_active: true
          }]).select().single();

          if (profError) {
             if (profError.message.toLowerCase().includes('security') || profError.message.toLowerCase().includes('rls')) {
                throw new Error("RLS POLICY ERROR: Missing 'Profiles' insert policy. Click 'Get SQL Fix' below.");
              }
            throw profError;
          }
          onLogin(profile);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Verification failed.');
      if (err.message.toLowerCase().includes('security') || err.message.toLowerCase().includes('rls')) {
        setShowSql(true);
        setDbStatus('rls_blocked');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleInitializeDemo = async () => {
    setIsSeeding(true);
    setError('');

    const steps: SeedStatus[] = PREDEFINED_ACCOUNTS.map(acc => ({
      email: acc.email,
      role: acc.user.role,
      status: 'pending'
    }));
    setSeedStep(steps);

    for (let i = 0; i < PREDEFINED_ACCOUNTS.length; i++) {
      const account = PREDEFINED_ACCOUNTS[i];
      setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'loading' } : s));

      try {
        const { data: authData, error: signUpError } = await supabase.auth.signUp({
          email: account.email,
          password: account.password,
          options: { data: { full_name: account.user.full_name, role: account.user.role } }
        });

        let userId = authData?.user?.id;

        if (signUpError?.message?.includes('already registered')) {
          const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email: account.email,
            password: account.password
          });
          if (signInError) throw signInError;
          userId = signInData.user?.id;
        } else if (signUpError) {
          throw signUpError;
        }

        if (userId) {
          const { error: profileError } = await supabase.from('profiles').upsert([{
            id: userId,
            username: account.user.username,
            full_name: account.user.full_name,
            role: account.user.role,
            is_active: true
          }]);

          if (profileError) throw profileError;

          setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'success' } : s));
        }

        await supabase.auth.signOut();
      } catch (err: any) {
        setSeedStep(prev => prev.map((s, idx) => idx === i ? { ...s, status: 'error', message: err.message } : s));
      }
    }
    checkDatabase();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          {/* Status Bar */}
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${
                dbStatus === 'online' ? 'bg-teal-400' : 
                dbStatus === 'rls_blocked' ? 'bg-amber-500' : 'bg-red-500'
              } shadow-[0_0_8px_currentColor]`}></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">
                {dbStatus === 'online' ? 'System Synced' : 
                 dbStatus === 'rls_blocked' ? 'RLS Policy Blocked' : 
                 dbStatus === 'missing_tables' ? 'Tables Missing' : 'Checking Connectivity'}
              </span>
            </div>
            <button onClick={checkDatabase} className="text-white/40 hover:text-white transition-colors">
              <Terminal size={12} />
            </button>
          </div>

          {showSql ? (
            <div className="p-8 bg-slate-900 text-teal-400 space-y-5 animate-in zoom-in-95 duration-300">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-2 text-white/70">
                  <ServerCrash size={16} className="text-red-400" />
                  <h3 className="text-[10px] font-black uppercase tracking-widest">Database Sync Fix</h3>
                </div>
                <button onClick={() => setShowSql(false)} className="text-white/40 hover:text-white"><X size={16} /></button>
              </div>

              <div className="p-4 bg-slate-800 rounded-xl border border-slate-700">
                <p className="text-[10px] text-teal-100/70 font-bold uppercase mb-2 flex items-center gap-2">
                  <Info size={12} /> Instructions
                </p>
                <ol className="text-[10px] text-teal-100/50 space-y-1 ml-4 list-decimal">
                  <li>Copy the script below.</li>
                  <li>Go to your <strong>Supabase Dashboard</strong>.</li>
                  <li>Click <strong>SQL Editor</strong> in the sidebar.</li>
                  <li>Paste and click <strong>Run</strong>.</li>
                </ol>
              </div>

              <div className="bg-black/60 p-5 rounded-xl border border-white/5 font-mono text-[9px] overflow-x-auto max-h-48 whitespace-pre text-teal-300 custom-scrollbar">
                {generateSql()}
              </div>

              <div className="flex gap-2">
                <button 
                  onClick={copyToClipboard}
                  className="flex-1 py-4 bg-teal-500 text-slate-900 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-teal-400 transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
                >
                  <Copy size={14} /> {copySuccess ? 'Copied to Clipboard' : 'Copy SQL Script'}
                </button>
              </div>
            </div>
          ) : isSeeding ? (
            <div className="p-8 space-y-4 animate-in fade-in">
              <div className="flex items-center gap-2 mb-2">
                <Zap size={14} className="text-amber-500 animate-pulse" />
                <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Registry Syncing...</span>
              </div>
              <div className="space-y-2">
                {seedStep.map((step, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{step.email}</span>
                      <span className="text-[9px] text-slate-400 font-bold uppercase">{step.role}</span>
                    </div>
                    {step.status === 'loading' ? (
                      <Loader2 size={16} className="animate-spin text-teal-600" />
                    ) : step.status === 'success' ? (
                      <CheckCircle2 size={16} className="text-teal-600" />
                    ) : (
                      <div className="w-4 h-4 rounded-full border border-slate-200"></div>
                    )}
                  </div>
                ))}
              </div>
              <button onClick={() => setIsSeeding(false)} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-xs uppercase shadow-xl hover:bg-slate-800">Return to Portal</button>
            </div>
          ) : (
            <>
              {(error || dbStatus === 'rls_blocked' || dbStatus === 'missing_tables') && (
                <div className="px-6 pt-6 animate-in slide-in-from-top-2">
                  <div className={`p-4 rounded-xl flex gap-3 border ${
                    dbStatus === 'rls_blocked' ? 'bg-amber-50 border-amber-200' : 'bg-red-50 border-red-200'
                  }`}>
                    <AlertTriangle className={dbStatus === 'rls_blocked' ? 'text-amber-600' : 'text-red-600'} size={18} />
                    <div>
                      <p className={`text-[10px] font-black uppercase tracking-widest ${
                        dbStatus === 'rls_blocked' ? 'text-amber-800' : 'text-red-800'
                      }`}>Database Setup Required</p>
                      <p className="text-[10px] text-slate-600 mt-1 font-medium leading-relaxed">
                        {dbStatus === 'rls_blocked' 
                          ? "Table security policies (RLS) are blocking your access." 
                          : "Tables are missing from your Supabase project."}
                      </p>
                      <button 
                        onClick={() => setShowSql(true)}
                        className={`mt-3 text-[9px] font-black uppercase text-white px-3 py-1.5 rounded-lg flex items-center gap-1.5 transition-all ${
                          dbStatus === 'rls_blocked' ? 'bg-amber-600 hover:bg-amber-700' : 'bg-red-600 hover:bg-red-700'
                        }`}
                      >
                        <Code size={12} /> Fix with SQL
                      </button>
                    </div>
                  </div>
                </div>
              )}

              <div className="p-10 pb-6 text-center">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl ring-4 ring-slate-50">
                  <ShieldCheck size={32} />
                </div>
                <h1 className="text-3xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
                <p className="text-slate-500 mt-2 text-[10px] font-black uppercase tracking-widest">Student Incident Registry</p>
              </div>

              <div className="px-10 flex border-b border-slate-100">
                <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign In</button>
                <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign Up</button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 pt-8 space-y-4">
                <div className="space-y-4">
                  {!isLoginMode && (
                    <div className="relative">
                      <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900" placeholder="Full Name" />
                    </div>
                  )}
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900" placeholder="Official Email" />
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900" placeholder="Password" />
                  </div>
                </div>

                <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase shadow-2xl active:scale-95 disabled:opacity-70 transition-all hover:bg-slate-800">
                  {isLoading ? <Loader2 size={18} className="animate-spin mx-auto" /> : isLoginMode ? 'Access Portal' : 'Register Account'}
                </button>
              </form>

              <div className="px-10 pb-10 space-y-6">
                <div className="grid grid-cols-3 gap-2">
                  {['teacher', 'counselor', 'admin'].map(type => (
                    <button key={type} onClick={() => { setEmail(`${type}@gmail.com`); setPassword('12345678'); setIsLoginMode(true); }} className="py-2 border border-slate-200 rounded-xl text-[9px] font-black uppercase text-slate-600 hover:bg-slate-50 transition-all">{type}</button>
                  ))}
                </div>
                <button onClick={handleInitializeDemo} className="w-full py-4 bg-teal-50 text-teal-700 border border-teal-100 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2 hover:bg-teal-100 transition-all shadow-sm">
                  <Database size={14} /> Initialize Demo Registry
                </button>
              </div>
            </>
          )}
        </div>
        <p className="text-slate-400 text-[9px] text-center uppercase tracking-widest font-black flex items-center justify-center gap-2">
          <Shield size={10} className="text-teal-600" /> Secure Educational Portal • v2.5
        </p>
      </div>
    </div>
  );
};

export default Login;

