import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  const addSystemLog = async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    try {
      const { data: logEntry } = await supabase.from('system_audit_logs').insert([{
        user_id: currentUser.id, user_name: currentUser.full_name, action, category, ip_address: 'Web-Client'
      }]).select().single();
      if (logEntry) setSystemLogs(prev => [logEntry as any, ...prev]);
    } catch (e) {
      console.error("Failed to log audit event:", e);
    }
  };

  const syncUserProfile = async (authUser: any) => {
    const { data: profile, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', authUser.id)
      .single();

    if (error || !profile) {
      console.warn("User authenticated but profile missing. Attempting auto-sync...");
      const email = authUser.email || '';
      const guessedRole = email.toLowerCase().startsWith('admin') ? 'Administrator' : 
                         email.toLowerCase().startsWith('counselor') ? 'Counselor' : 
                         authUser.user_metadata?.role || 'Teacher';

      const { data: newProfile } = await supabase.from('profiles').upsert([{
        id: authUser.id,
        username: email.split('@')[0],
        full_name: authUser.user_metadata?.full_name || 'Restored User',
        role: guessedRole,
        is_active: true
      }]).select().single();

      return newProfile;
    }
    return profile;
  };

  useEffect(() => {
    const initializeAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const profile = await syncUserProfile(session.user);
        if (profile) setCurrentUser(profile);
      }
      setIsInitializing(false);
    };
    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        const profile = await syncUserProfile(session.user);
        if (profile) setCurrentUser(profile);
      } else {
        setCurrentUser(null);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!currentUser) return;

    const fetchData = async () => {
      const [
        { data: stData },
        { data: incData },
        { data: typeData },
        { data: intData },
        { data: logData },
        { data: parentData },
        { data: repData },
        { data: auditData },
        { data: notifData }
      ] = await Promise.all([
        supabase.from('students').select('*').order('last_name'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*').order('start_date', { ascending: false }),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*').order('date_generated', { ascending: false }),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').eq('user_id', currentUser.id).order('created_at', { ascending: false })
      ]);

      if (stData) setStudents(stData);
      if (incData) setIncidents(incData);
      if (typeData) setIncidentTypes(typeData);
      if (intData) setInterventions(intData);
      if (logData) setDeviceLogs(logData as any);
      if (parentData) setParents(parentData);
      if (repData) setReports(repData as any);
      if (auditData) setSystemLogs(auditData as any);
      if (notifData) setNotifications(notifData.map(n => ({
        id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
      })));
    };

    fetchData();

    const channel = supabase.channel('realtime_updates')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${currentUser.id}` }, payload => {
        const n = payload.new;
        setNotifications(prev => [{
          id: n.id, title: n.title, message: n.message, timestamp: n.created_at, isRead: n.is_read, type: n.type
        }, ...prev]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [currentUser]);

  const handleLogout = async () => {
    await addSystemLog('User Initiated Logout', 'Access');
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const addNotification = async (notif: Omit<Notification, 'id' | 'timestamp' | 'isRead'>, userId?: string) => {
    const targetUserId = userId || currentUser?.id;
    if (!targetUserId) return;
    await supabase.from('notifications').insert([{
      user_id: targetUserId, title: notif.title, message: notif.message, type: notif.type, is_read: false
    }]);
  };

  const addStudent = async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select().single();
    if (data) {
      setStudents(prev => [...prev, data].sort((a,b) => a.last_name.localeCompare(b.last_name)));
      addSystemLog(`Added new student: ${data.first_name} ${data.last_name}`, 'Registry');
    }
    return { data, error };
  };

  const addIncident = async (newInc: Partial<Incident>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('incidents').insert([{
      student_id: newInc.student_id, reported_by_user_id: currentUser.id, incident_type_id: newInc.incident_type_id,
      location: newInc.location, description: newInc.description, immediate_action: newInc.immediate_action,
      status: 'Pending', date_occurred: new Date().toISOString()
    }]).select().single();

    if (data) {
      setIncidents(prev => [data, ...prev]);
      const student = students.find(s => s.id === data.student_id);
      addNotification({
        title: 'New Incident Reported',
        message: `${student?.last_name} report: ${data.description.substring(0, 40)}...`,
        type: 'incident'
      });
      addSystemLog(`Registered incident for ${student?.last_name}`, 'Registry');
    }
  };

  const updateIncidentStatus = async (id: string, status: Incident['status']) => {
    const { data } = await supabase.from('incidents').update({ status }).eq('id', id).select().single();
    if (data) {
      setIncidents(prev => prev.map(inc => inc.id === id ? data : inc));
      addSystemLog(`Updated Incident Status to ${status}`, 'Audit');
    }
  };

  const addIntervention = async (intData: Partial<BehavioralIntervention>) => {
    if (!currentUser) return;
    const { data } = await supabase.from('interventions').insert([{
      ...intData, assigned_by_user_id: currentUser.id
    }]).select().single();
    if (data) {
      setInterventions(prev => [data, ...prev]);
      addSystemLog(`Initialized intervention for student ID: ${data.student_id}`, 'Registry');
    }
  };

  const addGeneratedReport = async (report: GeneratedReport) => {
    if (!currentUser) return;
    const { data } = await supabase.from('generated_reports').insert([{
      title: report.title, type: report.type, generated_by_user_id: currentUser.id, status: 'Ready', file_size: report.file_size
    }]).select().single();
    if (data) setReports(prev => [data as any, ...prev]);
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-slate-900 rounded-xl mb-4 flex items-center justify-center text-white font-black shadow-xl">S</div>
          <div className="h-4 w-32 bg-slate-200 rounded"></div>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={(u) => { setCurrentUser(u); addSystemLog('Login Success', 'Access'); }} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={incidents} students={students} />;
      case 'Students': return <Students currentUser={currentUser} incidents={incidents} students={students} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={addStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={incidents} students={students} incidentTypes={incidentTypes} onAddIncident={addIncident as any} onUpdateStatus={updateIncidentStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={students} interventions={interventions} onAddIntervention={addIntervention} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={addGeneratedReport} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement />;
      default: return <Dashboard incidents={incidents} students={students} />;
    }
  };

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={async () => {
      await supabase.from('notifications').update({ is_read: true }).eq('user_id', currentUser.id);
      setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
    }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

