import React, { useState, useEffect, useCallback } from 'react';
import { Database, ShieldCheck, Loader2, AlertCircle } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS,
  PREDEFINED_ACCOUNTS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [localMode, setLocalMode] = useState(false);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [registryUsers, setRegistryUsers] = useState<User[]>([]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog: SystemLog = {
      id: `sl-${Date.now()}`,
      timestamp: new Date().toISOString(),
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: localMode ? 'Local-Bypass' : 'Supabase-Registry'
    };

    setSystemLogs(prev => [newLog, ...prev]);

    if (!localMode) {
      try {
        await supabase.from('system_audit_logs').insert([{
          user_id: currentUser.id,
          user_name: currentUser.full_name,
          action,
          category,
          ip_address: 'Supabase-Registry'
        }]);
      } catch (e) {
        console.error("Audit log sync failed:", e);
      }
    }
  }, [currentUser, localMode]);

  const fetchRegistryData = useCallback(async () => {
    if (localMode) {
      setStudents(MOCK_STUDENTS);
      setIncidents(MOCK_INCIDENTS);
      setIncidentTypes(MOCK_INCIDENT_TYPES);
      setInterventions(MOCK_INTERVENTIONS);
      setDeviceLogs(MOCK_DEVICE_LOGS);
      setParents(MOCK_PARENTS);
      setReports(MOCK_REPORTS);
      setSystemLogs(MOCK_SYSTEM_LOGS);
      setNotifications(MOCK_NOTIFICATIONS);
      setRegistryUsers(PREDEFINED_ACCOUNTS.map(a => a.user as User));
      setIsInitializing(false);
      return;
    }

    setIsSyncing(true);
    try {
      // Parallel fetch from Supabase
      const [
        { data: st }, { data: inc }, { data: it }, 
        { data: intr }, { data: dev }, { data: par }, 
        { data: rep }, { data: logs }, { data: prof }
      ] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*'),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }).limit(100),
        supabase.from('profiles').select('*')
      ]);

      // Populate state (fallback to MOCK if empty/error for demo purposes)
      setStudents(st && st.length > 0 ? st : MOCK_STUDENTS);
      setIncidents(inc && inc.length > 0 ? inc : MOCK_INCIDENTS);
      setIncidentTypes(it && it.length > 0 ? it : MOCK_INCIDENT_TYPES);
      setInterventions(intr && intr.length > 0 ? intr : MOCK_INTERVENTIONS);
      setDeviceLogs(dev && dev.length > 0 ? dev : MOCK_DEVICE_LOGS);
      setParents(par && par.length > 0 ? par : MOCK_PARENTS);
      setReports(rep && rep.length > 0 ? rep : MOCK_REPORTS);
      setSystemLogs(logs && logs.length > 0 ? logs : MOCK_SYSTEM_LOGS);
      setRegistryUsers(prof && prof.length > 0 ? prof : PREDEFINED_ACCOUNTS.map(a => a.user as User));
      setNotifications(MOCK_NOTIFICATIONS);
    } catch (error) {
      console.error("Registry fetch failed, defaulting to Local Resilience Mode:", error);
      setStudents(MOCK_STUDENTS);
      setIncidents(MOCK_INCIDENTS);
      setIncidentTypes(MOCK_INCIDENT_TYPES);
      setInterventions(MOCK_INTERVENTIONS);
      setDeviceLogs(MOCK_DEVICE_LOGS);
      setParents(MOCK_PARENTS);
      setReports(MOCK_REPORTS);
      setSystemLogs(MOCK_SYSTEM_LOGS);
    } finally {
      setIsSyncing(false);
      setIsInitializing(false);
    }
  }, [localMode]);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    } else {
      setIsInitializing(false);
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = () => {
    addSystemLog('User Initiated Logout', 'Access');
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleLocalBypass = (user: User) => {
    setLocalMode(true);
    setCurrentUser(user);
    setActiveTab('Dashboard');
    addSystemLog('Emergency Local Registry Bypass Activated', 'Access');
  };

  // --- Persistent Database Handlers ---

  const handleAddIncident = async (newInc: Partial<Incident>) => {
    const incData = {
      student_id: newInc.student_id!,
      reported_by_user_id: currentUser!.id,
      incident_type_id: newInc.incident_type_id!,
      date_reported: new Date().toISOString(),
      date_occurred: new Date().toISOString(),
      location: newInc.location!,
      description: newInc.description!,
      immediate_action: newInc.immediate_action!,
      status: 'Pending' as const
    };

    // Optimistic Update
    const tempInc: Incident = { id: `temp-${Date.now()}`, ...incData };
    setIncidents(prev => [tempInc, ...prev]);

    if (!localMode) {
      try {
        const { data, error } = await supabase.from('incidents').insert([incData]).select().single();
        if (error) throw error;
        // Replace temp with real record
        setIncidents(prev => prev.map(i => i.id === tempInc.id ? data : i));
        addSystemLog(`Synchronized Incident Report for Student: ${incData.student_id}`, 'Registry');
      } catch (err) {
        console.error("Supabase Save Error:", err);
        alert("Persistence failed. Incident remains in local session cache only.");
      }
    } else {
      addSystemLog(`Recorded Local Incident for Student: ${incData.student_id}`, 'Registry');
    }
  };

  const handleUpdateStatus = async (id: string, status: Incident['status']) => {
    // Optimistic Update
    setIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));

    if (!localMode && !id.startsWith('temp-')) {
      try {
        const { error } = await supabase.from('incidents').update({ status }).eq('id', id);
        if (error) throw error;
        addSystemLog(`Updated Incident #${id} status to ${status}`, 'Audit');
      } catch (err) {
        console.error("Status Sync Error:", err);
      }
    }
  };

  const handleAddStudent = async (data: Partial<Student>) => {
    const studentData = {
      lrn: data.lrn || '000000000000',
      first_name: data.first_name!,
      last_name: data.last_name!,
      date_of_birth: data.date_of_birth || new Date().toISOString(),
      gender: data.gender || 'Male',
      grade_level: data.grade_level || '7',
      section: data.section || 'N/A',
      address: data.address || 'N/A',
      contact_number: data.contact_number || 'N/A'
    };

    if (!localMode) {
      try {
        const { data: remoteStudent, error } = await supabase.from('students').insert([studentData]).select().single();
        if (error) throw error;
        setStudents(prev => [remoteStudent, ...prev]);
        addSystemLog(`Committed New Subject to Supabase: ${studentData.first_name} ${studentData.last_name}`, 'Registry');
        return { data: remoteStudent, error: null };
      } catch (err) {
        console.error("Student Sync Error:", err);
        const localStudent = { id: `local-${Date.now()}`, ...studentData };
        setStudents(prev => [localStudent, ...prev]);
        return { data: localStudent, error: null };
      }
    } else {
      const s = { id: `s-${Date.now()}`, ...studentData };
      setStudents(prev => [s, ...prev]);
      addSystemLog(`Added Local Subject: ${s.first_name} ${s.last_name}`, 'Registry');
      return { data: s, error: null };
    }
  };

  const handleAddIntervention = async (data: Partial<BehavioralIntervention>) => {
    const intrData = {
      student_id: data.student_id!,
      assigned_by_user_id: currentUser!.id,
      intervention_type: data.intervention_type!,
      description: data.description!,
      start_date: new Date().toISOString(),
      status: 'Active'
    };

    if (!localMode) {
      try {
        const { data: remoteIntr, error } = await supabase.from('interventions').insert([intrData]).select().single();
        if (error) throw error;
        setInterventions(prev => [remoteIntr, ...prev]);
        addSystemLog(`Persisted Intervention Plan for: ${intrData.student_id}`, 'Registry');
      } catch (err) {
        console.error("Intervention Sync Error:", err);
      }
    } else {
      const int = { id: `int-${Date.now()}`, ...intrData };
      setInterventions(prev => [int, ...prev]);
    }
  };

  const handleGenerateReport = async (report: GeneratedReport) => {
    setReports(prev => [report, ...prev]);
    if (!localMode) {
      try {
        await supabase.from('generated_reports').insert([{
          title: report.title,
          type: report.type,
          generated_by_user_id: currentUser!.id,
          status: report.status,
          file_size: report.file_size,
          date_generated: report.date_generated
        }]);
        addSystemLog(`Audit Report Saved to Registry: ${report.title}`, 'Audit');
      } catch (e) {
        console.error("Report Sync failed:", e);
      }
    }
  };

  const handleUpdateUser = async (id: string, updates: Partial<User>) => {
    setRegistryUsers(prev => prev.map(u => u.id === id ? { ...u, ...updates } : u));
    if (!localMode) {
      try {
        const { error } = await supabase.from('profiles').update(updates).eq('id', id);
        if (error) throw error;
        addSystemLog(`Modified Authority Clearance for Registry User: ${id}`, 'Security');
      } catch (e) {
        console.error("Profile sync failed:", e);
      }
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={incidents} students={students} deviceLogs={deviceLogs} />;
      case 'Students': return <Students currentUser={currentUser} incidents={incidents} students={students} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={handleAddStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={incidents} students={students} incidentTypes={incidentTypes} onAddIncident={handleAddIncident} onUpdateStatus={handleUpdateStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={students} interventions={interventions} onAddIntervention={handleAddIntervention} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={handleGenerateReport} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement localUsers={registryUsers} onUpdateUser={handleUpdateUser} onSync={fetchRegistryData} />;
      default: return <Dashboard incidents={incidents} students={students} deviceLogs={deviceLogs} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black animate-bounce shadow-2xl">S</div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Synchronizing Authority Registry...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={handleLocalBypass} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => setNotifications(prev => prev.map(n => ({...n, isRead: true})))}>
      {isSyncing && (
        <div className="fixed bottom-8 right-8 bg-slate-900 text-white px-4 py-2 rounded-full flex items-center gap-2 shadow-2xl z-50 animate-in slide-in-from-bottom-4">
          <Loader2 size={14} className="animate-spin text-teal-400" />
          <span className="text-[9px] font-black uppercase tracking-widest">Registry Sync Active</span>
        </div>
      )}
      {localMode && (
        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-xl flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-3">
            <AlertCircle size={18} className="text-amber-700" />
            <div>
              <p className="text-xs font-black uppercase tracking-widest text-amber-900">Offline Resilience Mode</p>
              <p className="text-[10px] text-amber-700 font-medium leading-relaxed">Changes are cached in session memory. Reconnect to sync with Supabase Registry.</p>
            </div>
          </div>
          <button onClick={() => setLocalMode(false)} className="px-3 py-1.5 bg-amber-900 text-white text-[9px] font-black uppercase tracking-widest rounded-lg">Try Syncing</button>
        </div>
      )}
      {renderContent()}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

/**
 * Analyze student behavioral history using Gemini 3 Pro.
 * Adheres to strict @google/genai SDK guidelines.
 */
export const getBehavioralInsight = async (studentHistory: any[]) => {
  // Use a fresh instance with the environment-provided API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an expert educational psychologist. 
    Analyze the following student incident history and provide a professional assessment.

    Student Incident Data:
    ${JSON.stringify(studentHistory)}

    Format your response as a JSON object adhering to the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2048 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            suggestedInterventions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            growthFocus: { type: Type.STRING }
          },
          required: ["analysis", "riskLevel", "suggestedInterventions", "growthFocus"]
        }
      }
    });

    // Access .text property directly as per guidelines
    const resultText = response.text?.trim() || "{}";
    return JSON.parse(resultText);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return {
      analysis: "Automated analysis failed. Manual review of case logs is required.",
      riskLevel: "Undetermined",
      suggestedInterventions: ["Verify primary student contact details.", "Schedule observation period."],
      growthFocus: "General self-regulation."
    };
  }
};

import React, { useMemo, useState, useRef } from 'react';
import { AlertTriangle, Plus, Search, Eye, Download, X, MoreVertical, ShieldCheck, Mic, MicOff, Loader2, BrainCircuit } from 'lucide-react';
import { User, Incident, Student, IncidentType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface IncidentsProps {
  currentUser: User;
  incidents: Incident[];
  students: Student[];
  incidentTypes: IncidentType[];
  onAddIncident: (inc: Partial<Incident>) => void;
  onUpdateStatus: (id: string, status: Incident['status']) => void;
  searchQuery: string;
}

const Incidents: React.FC<IncidentsProps> = ({ currentUser, incidents, students, incidentTypes, onAddIncident, onUpdateStatus, searchQuery }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDictating, setIsDictating] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [newIncident, setNewIncident] = useState({ student_id: '', incident_type_id: '', location: '', description: '', immediate_action: '' });

  const recognitionRef = useRef<any>(null);

  const visibleIncidents = useMemo(() => {
    let filtered = [...incidents];
    if (currentUser.role === 'Teacher') {
      filtered = filtered.filter(inc => inc.reported_by_user_id === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(inc => {
        const s = students.find(st => st.id === inc.student_id);
        return (
          s?.first_name.toLowerCase().includes(q) || 
          s?.last_name.toLowerCase().includes(q) || 
          inc.description.toLowerCase().includes(q)
        );
      });
    }
    return filtered;
  }, [currentUser, incidents, searchQuery, students]);

  const toggleDictation = () => {
    if (isDictating) {
      recognitionRef.current?.stop();
      setIsDictating(false);
    } else {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (!SpeechRecognition) {
        alert("Voice registry is not supported in this browser.");
        return;
      }
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[event.results.length - 1][0].transcript;
        setNewIncident(prev => ({ ...prev, description: prev.description + transcript }));
      };
      recognitionRef.current.start();
      setIsDictating(true);
    }
  };

  const handleAiRefinement = async () => {
    if (!newIncident.description) return;
    setIsProcessingAI(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Rewrite this behavioral observation into a professional, objective, and clear incident report: "${newIncident.description}"`
      });
      if (response.text) {
        setNewIncident(prev => ({ ...prev, description: response.text }));
      }
    } catch (e) {
      console.error("AI refinement failed:", e);
      alert("AI Service currently unavailable. Manual editing required.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddIncident(newIncident);
    setIsModalOpen(false);
    setNewIncident({ student_id: '', incident_type_id: '', location: '', description: '', immediate_action: '' });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between md:items-end gap-6 border-b border-slate-200 pb-8">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Assistance Records</h2>
          <p className="text-slate-500 font-medium">Official registry for behavioral monitoring and event tracking.</p>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 active:scale-95">
          <Plus size={16} /> Report New Event
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nature of Event</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Subject</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {visibleIncidents.map((inc) => {
                const student = students.find(s => s.id === inc.student_id);
                const type = incidentTypes.find(t => t.id === inc.incident_type_id);
                return (
                  <tr key={inc.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-8 py-5">
                      <p className="text-sm font-bold text-slate-900">{type?.name || 'Behavioral Report'}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter truncate max-w-xs">{inc.description}</p>
                    </td>
                    <td className="px-8 py-5 text-sm font-bold text-slate-800">{student ? `${student.first_name} ${student.last_name}` : 'N/A'}</td>
                    <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(inc.date_reported).toLocaleDateString()}</td>
                    <td className="px-8 py-5">
                      <select 
                        disabled={currentUser.role === 'Teacher'} 
                        value={inc.status} 
                        onChange={(e) => onUpdateStatus(inc.id, e.target.value as any)} 
                        className={`px-3 py-1.5 rounded text-[10px] font-black uppercase tracking-widest border transition-colors outline-none cursor-pointer ${
                          inc.status === 'Resolved' ? 'bg-teal-50 text-teal-700 border-teal-100' : 'bg-amber-50 text-amber-700 border-amber-100'
                        }`}
                      >
                        <option value="Pending">Pending</option>
                        <option value="Investigating">Investigating</option>
                        <option value="Resolved">Resolved</option>
                        <option value="Closed">Closed</option>
                      </select>
                    </td>
                    <td className="px-8 py-5 text-right"><Eye size={16} className="ml-auto text-slate-300 hover:text-slate-900 cursor-pointer" /></td>
                  </tr>
                );
              })}
              {visibleIncidents.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-12 text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">No registry records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-2">
                <ShieldCheck size={18} className="text-teal-600" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Official Event Registry</h3>
              </div>
              <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Subject</label>
                  <select required value={newIncident.student_id} onChange={(e) => setNewIncident({...newIncident, student_id: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:ring-1 focus:ring-teal-500">
                    <option value="">Select Student</option>
                    {students.map(s => <option key={s.id} value={s.id}>{s.last_name}, {s.first_name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Nature</label>
                  <select required value={newIncident.incident_type_id} onChange={(e) => setNewIncident({...newIncident, incident_type_id: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:ring-1 focus:ring-teal-500">
                    <option value="">Select Type</option>
                    {incidentTypes.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Location</label>
                <input required type="text" value={newIncident.location} onChange={(e) => setNewIncident({...newIncident, location: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:ring-1 focus:ring-teal-500" placeholder="e.g. Science Lab, Corridor" />
              </div>
              <div className="relative">
                <div className="flex justify-between items-center mb-1">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Event Narrative</label>
                  <div className="flex gap-2">
                    <button type="button" onClick={handleAiRefinement} disabled={isProcessingAI || !newIncident.description} className="text-[9px] font-black uppercase text-teal-600 hover:text-teal-800 disabled:opacity-50 flex items-center gap-1 transition-colors">
                      {isProcessingAI ? <Loader2 size={10} className="animate-spin" /> : <BrainCircuit size={10} />}
                      AI Refine
                    </button>
                    <button type="button" onClick={toggleDictation} className={`p-1.5 rounded-full transition-all ${isDictating ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}>
                      {isDictating ? <MicOff size={14} /> : <Mic size={14} />}
                    </button>
                  </div>
                </div>
                <textarea required value={newIncident.description} onChange={(e) => setNewIncident({...newIncident, description: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm min-h-[120px] outline-none focus:ring-1 focus:ring-teal-500" placeholder="Detailed objective observation..." />
              </div>
              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-lg text-xs font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl active:scale-95">Submit Official Report</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Incidents;

import React, { useState, useRef, useEffect } from 'react';
import { NAV_ITEMS } from '../constants';
import { User, Notification } from '../types';
import { LogOut, Bell, Search, ShieldCheck, AlertCircle, FileText, Settings, Clock, CheckCircle } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  user: User;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
  notifications: Notification[];
  onMarkRead: () => void;
}

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  user, 
  activeTab, 
  setActiveTab, 
  onLogout, 
  searchQuery, 
  setSearchQuery,
  notifications,
  onMarkRead
}) => {
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  const filteredNavItems = NAV_ITEMS.filter(item => item.roles.includes(user.role));
  const unreadCount = notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
        setIsNotifOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getNotifIcon = (type: Notification['type']) => {
    switch (type) {
      case 'incident': return <AlertCircle size={14} className="text-amber-500" />;
      case 'report': return <FileText size={14} className="text-teal-500" />;
      case 'system': return <Settings size={14} className="text-slate-500" />;
      default: return <Bell size={14} className="text-slate-500" />;
    }
  };

  const formatTime = (isoString: string) => {
    const date = new Date(isoString);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return `${mins}m ago`;
    const hours = Math.floor(mins / 60);
    if (hours < 24) return `${hours}h ago`;
    return date.toLocaleDateString();
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <aside className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col shadow-2xl z-20">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-8 bg-teal-600 rounded flex items-center justify-center text-white">
              <ShieldCheck size={18} />
            </div>
            <h1 className="text-xl font-bold text-white tracking-wider">SAFE-EDU</h1>
          </div>
          <p className="text-[8px] font-black text-teal-500/60 uppercase tracking-[0.2em] mb-10 leading-relaxed px-1">
            Student Assistance & Fostering Excellence in EDUcation
          </p>

          <nav className="space-y-1">
            {filteredNavItems.map((item) => (
              <button
                key={item.name}
                onClick={() => setActiveTab(item.name)}
                className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg text-xs font-bold uppercase tracking-widest transition-all ${
                  activeTab === item.name 
                    ? 'bg-teal-700 text-white shadow-lg' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800'
                }`}
              >
                {item.icon}
                {item.name}
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-6 border-t border-slate-800 bg-slate-900/50">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-10 h-10 shrink-0 rounded-lg bg-slate-800 flex items-center justify-center text-sm font-bold text-teal-500 border border-slate-700">
              {user.full_name.split(' ').map(n => n[0]).join('')}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-bold text-white truncate uppercase tracking-tighter">{user.full_name}</p>
              <p className="text-[10px] text-teal-600 font-bold uppercase tracking-widest">{user.role}</p>
            </div>
          </div>
          <button 
            onClick={onLogout}
            className="w-full flex items-center justify-center gap-2 px-3 py-2.5 text-xs text-white bg-slate-800 border border-slate-700 hover:bg-red-900/20 hover:text-red-400 hover:border-red-900/50 rounded-lg font-bold uppercase tracking-widest transition-all"
          >
            <LogOut size={14} />
            Logout
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm relative z-30">
          <div className="relative w-96 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-teal-600 transition-colors" size={16} />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search Student ID, Name or Incident..."
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-md text-sm focus:ring-1 focus:ring-teal-500 transition-all outline-none placeholder:text-slate-400 font-medium"
            />
          </div>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-teal-50 rounded-full border border-teal-100">
              <div className="w-2 h-2 rounded-full bg-teal-500 animate-pulse"></div>
              <span className="text-[10px] font-black text-teal-700 uppercase tracking-widest">Protocol Active</span>
            </div>

            <div className="relative" ref={notifRef}>
              <button 
                onClick={() => setIsNotifOpen(!isNotifOpen)}
                className={`p-2 rounded-full transition-all relative ${isNotifOpen ? 'bg-slate-100 text-teal-600' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
              >
                <Bell size={18} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 border-2 border-white rounded-full"></span>
                )}
              </button>

              {isNotifOpen && (
                <div className="absolute right-0 mt-3 w-80 bg-white border border-slate-200 rounded-xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                  <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-800">Notifications</h3>
                    {unreadCount > 0 && (
                      <button 
                        onClick={onMarkRead}
                        className="text-[9px] font-black uppercase tracking-widest text-teal-600 hover:text-teal-800 transition-colors flex items-center gap-1"
                      >
                        <CheckCircle size={10} /> Mark all read
                      </button>
                    )}
                  </div>
                  <div className="max-h-96 overflow-y-auto divide-y divide-slate-50">
                    {notifications.length > 0 ? (
                      notifications.map((n) => (
                        <div key={n.id} className={`p-4 hover:bg-slate-50 transition-colors flex gap-3 ${!n.isRead ? 'bg-teal-50/20' : ''}`}>
                          <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${!n.isRead ? 'bg-white shadow-sm' : 'bg-slate-100 opacity-60'}`}>
                            {getNotifIcon(n.type)}
                          </div>
                          <div className="flex-1 overflow-hidden">
                            <div className="flex justify-between items-start gap-2">
                              <p className={`text-xs font-bold truncate ${!n.isRead ? 'text-slate-900' : 'text-slate-500'}`}>{n.title}</p>
                              <span className="text-[9px] font-bold text-slate-400 whitespace-nowrap"><Clock size={8} className="inline mr-1" />{formatTime(n.timestamp)}</span>
                            </div>
                            <p className={`text-[10px] leading-relaxed mt-0.5 ${!n.isRead ? 'text-slate-600 font-medium' : 'text-slate-400'}`}>{n.message}</p>
                          </div>
                          {!n.isRead && <div className="w-1.5 h-1.5 rounded-full bg-teal-500 mt-1.5"></div>}
                        </div>
                      ))
                    ) : (
                      <div className="p-8 text-center">
                        <Bell size={24} className="mx-auto text-slate-200 mb-2" />
                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Registry is clear</p>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-8 bg-slate-50/50">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </section>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useCallback } from 'react';
import { Database, ShieldCheck, Loader2, AlertCircle, CloudCheck } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS,
  PREDEFINED_ACCOUNTS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [localMode, setLocalMode] = useState(false);

  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [registryUsers, setRegistryUsers] = useState<User[]>([]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog: SystemLog = {
      id: `sl-${Date.now()}`,
      timestamp: new Date().toISOString(),
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: localMode ? 'Local-Session' : 'Registry-Sync'
    };

    setSystemLogs(prev => [newLog, ...prev]);

    if (!localMode) {
      try {
        await supabase.from('system_audit_logs').insert([{
          user_id: currentUser.id,
          user_name: currentUser.full_name,
          action,
          category,
          ip_address: 'Registry-Sync'
        }]);
      } catch (e) {
        console.warn("Audit Log Sync Failed:", e);
      }
    }
  }, [currentUser, localMode]);

  const fetchRegistryData = useCallback(async () => {
    if (localMode) {
      setStudents(MOCK_STUDENTS);
      setIncidents(MOCK_INCIDENTS);
      setIncidentTypes(MOCK_INCIDENT_TYPES);
      setInterventions(MOCK_INTERVENTIONS);
      setDeviceLogs(MOCK_DEVICE_LOGS);
      setParents(MOCK_PARENTS);
      setReports(MOCK_REPORTS);
      setSystemLogs(MOCK_SYSTEM_LOGS);
      setNotifications(MOCK_NOTIFICATIONS);
      setRegistryUsers(PREDEFINED_ACCOUNTS.map(a => a.user as User));
      setIsInitializing(false);
      return;
    }

    setIsSyncing(true);
    try {
      const [st, inc, it, intr, dev, par, rep, logs, prof] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*'),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }).limit(100),
        supabase.from('profiles').select('*')
      ]);

      setStudents(st.data && st.data.length > 0 ? st.data : MOCK_STUDENTS);
      setIncidents(inc.data && inc.data.length > 0 ? inc.data : MOCK_INCIDENTS);
      setIncidentTypes(it.data && it.data.length > 0 ? it.data : MOCK_INCIDENT_TYPES);
      setInterventions(intr.data && intr.data.length > 0 ? intr.data : MOCK_INTERVENTIONS);
      setDeviceLogs(dev.data && dev.data.length > 0 ? dev.data : MOCK_DEVICE_LOGS);
      setParents(par.data && par.data.length > 0 ? par.data : MOCK_PARENTS);
      setReports(rep.data && rep.data.length > 0 ? rep.data : MOCK_REPORTS);
      setSystemLogs(logs.data && logs.data.length > 0 ? logs.data : MOCK_SYSTEM_LOGS);
      setRegistryUsers(prof.data && prof.data.length > 0 ? prof.data : PREDEFINED_ACCOUNTS.map(a => a.user as User));
      setNotifications(MOCK_NOTIFICATIONS);
    } catch (error) {
      console.error("Supabase Registry Fetch Failed. Entering Resilience Mode.", error);
      setLocalMode(true);
    } finally {
      setIsSyncing(false);
      setIsInitializing(false);
    }
  }, [localMode]);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    } else {
      setIsInitializing(false);
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = () => {
    addSystemLog('Session Terminated', 'Access');
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleAddIncident = async (newInc: Partial<Incident>) => {
    const incData = {
      student_id: newInc.student_id!,
      reported_by_user_id: currentUser!.id,
      incident_type_id: newInc.incident_type_id!,
      date_reported: new Date().toISOString(),
      date_occurred: new Date().toISOString(),
      location: newInc.location!,
      description: newInc.description!,
      immediate_action: newInc.immediate_action!,
      status: 'Pending' as const
    };

    const tempId = `temp-${Date.now()}`;
    setIncidents(prev => [{ id: tempId, ...incData } as Incident, ...prev]);

    if (!localMode) {
      try {
        const { data, error } = await supabase.from('incidents').insert([incData]).select().single();
        if (error) throw error;
        setIncidents(prev => prev.map(i => i.id === tempId ? data : i));
        addSystemLog(`Committed Incident to Registry`, 'Registry');
      } catch (err) {
        console.error("Sync Error:", err);
        alert("Persistance failure. Record saved to local session only.");
      }
    }
  };

  const handleUpdateStatus = async (id: string, status: Incident['status']) => {
    setIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
    if (!localMode && !id.startsWith('temp-')) {
      try {
        const { error } = await supabase.from('incidents').update({ status }).eq('id', id);
        if (error) throw error;
        addSystemLog(`Status Update Confirmed: #${id}`, 'Audit');
      } catch (err) {
        console.error("Update Sync Error:", err);
      }
    }
  };

  const handleAddStudent = async (data: Partial<Student>) => {
    const studentData = {
      lrn: data.lrn || '000000000000',
      first_name: data.first_name!,
      last_name: data.last_name!,
      date_of_birth: data.date_of_birth || new Date().toISOString(),
      gender: data.gender || 'Male',
      grade_level: data.grade_level || '7',
      section: data.section || 'N/A',
      address: data.address || 'N/A',
      contact_number: data.contact_number || 'N/A'
    };

    if (!localMode) {
      try {
        const { data: remoteStudent, error } = await supabase.from('students').insert([studentData]).select().single();
        if (error) throw error;
        setStudents(prev => [remoteStudent, ...prev]);
        addSystemLog(`Added Learner: ${studentData.last_name}`, 'Registry');
        return { data: remoteStudent, error: null };
      } catch (err) {
        console.error("Persistence Error:", err);
        const local = { id: `local-${Date.now()}`, ...studentData } as Student;
        setStudents(prev => [local, ...prev]);
        return { data: local, error: null };
      }
    } else {
      const s = { id: `s-${Date.now()}`, ...studentData } as Student;
      setStudents(prev => [s, ...prev]);
      return { data: s, error: null };
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={incidents} students={students} deviceLogs={deviceLogs} />;
      case 'Students': return <Students currentUser={currentUser} incidents={incidents} students={students} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={handleAddStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={incidents} students={students} incidentTypes={incidentTypes} onAddIncident={handleAddIncident} onUpdateStatus={handleUpdateStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={students} interventions={interventions} onAddIntervention={async (d) => {
          setInterventions(prev => [{ id: `temp-${Date.now()}`, ...d, status: 'Active' } as BehavioralIntervention, ...prev]);
          if (!localMode) await supabase.from('interventions').insert([{ ...d, status: 'Active' }]);
        }} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={(r) => setReports(prev => [r, ...prev])} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement localUsers={registryUsers} onUpdateUser={async (id, up) => {
          setRegistryUsers(prev => prev.map(u => u.id === id ? { ...u, ...up } : u));
          if (!localMode) await supabase.from('profiles').update(up).eq('id', id);
        }} onSync={fetchRegistryData} />;
      default: return <Dashboard incidents={incidents} students={students} deviceLogs={deviceLogs} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black animate-bounce shadow-2xl">S</div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Verifying System Integrity...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={(u) => { setLocalMode(true); setCurrentUser(u); }} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => setNotifications(prev => prev.map(n => ({...n, isRead: true})))}>
